import { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import type {
  Spool, PresetVendor, MachineItem, AmsData, AmsUnit, AmsTray,
  BridgeResponseBody, CandidateColor, FilamentColorCodesResponse,
} from './types';
import { BAMBU_COLORS, formatTypeSeries } from './constants';
import { SpoolColorChip } from './SpoolColorChip';
import useStore from '../../store/AppStore';
import { useDeviceBridge } from '../../hooks/Bridge';
import { buildVendorOptions } from './vendorOptions';
// STUDIO-18114: shared draft -> commit helper for the custom color picker so
// the OK/Cancel popover and the existing edit-dialog state stay aligned.
import { commitCustomColorSelection } from './customColorSelection';
import {
  canonicalizeHex,
  cssBackgroundFor,
  candidateMatchesFormState,
} from './colors';
// STUDIO-18344: shared AMS-tray -> Spool payload helper. Single-select still
// goes through the editable form (so the user can review and tweak before
// saving), but multi-select uses these helpers directly so the wire payload
// matches an unedited single-slot save byte for byte.
import {
  buildSpoolFromTray,
  getTrayCurrentNetWeight,
  partitionTraysForBatchCreate,
} from './buildSpoolFromTray';
// STUDIO-18385: gate AMS save on duplicate RFID detection so users explicitly
// agree before an existing spool record is overwritten.
import { ConfirmDialog } from './ConfirmDialog';

// STUDIO-17959: cap both 当前净重 / 总净重 inputs in the Add/Edit dialog.
// Bug repro: users could type arbitrarily large numbers (e.g. 99999999999)
// into either weight field and submit. Backend then clamped/overflowed
// silently and the row's weight ended up persisted as 0, so the spool
// looked fully consumed in the manager. There was also no client-side
// check that currentNetWeight ≤ totalNetWeight (only `isValid` already had
// that one, but the missing max cap allowed the larger bug).
// Cap at 999_999_999g (~999 t) — fits in a signed 32-bit int (max
// 2_147_483_647) so we never overflow the wire format, while staying high
// enough that no realistic SKU will be rejected by the UI. Anything that
// would actually need more than this was always a typo; we only need a
// hard ceiling, not a tight one.
const MAX_NET_WEIGHT_GRAMS = 999_999_999;

function clampWeight(value: number): number {
  if (!Number.isFinite(value) || value < 0) return 0;
  return Math.min(MAX_NET_WEIGHT_GRAMS, Math.round(value));
}

// STUDIO-18125: footer quantity widget is bounded [1, 99]; floor (not round)
// so a paste like "1.9" can't bump the count up by one. Empty/NaN/<1 falls
// back to 1 because min=1 has no sane "empty" semantic.
function clampQuantity(value: number): number {
  if (!Number.isFinite(value) || value < 1) return 1;
  return Math.min(99, Math.floor(value));
}

// STUDIO-17977: legacy spelling kept as an alias of `canonicalizeHex` so
// existing call sites in this file (selectAmsSlot, handleSubmit AMS branch)
// don't churn during the colours/ extraction. New code should import
// `canonicalizeHex` from './colors' directly.
const normalizeColorCode = canonicalizeHex;

function isPresetColor(value: string): boolean {
  return BAMBU_COLORS.some((c) => c.toUpperCase() === value.toUpperCase());
}

function hasCloudRfid(tagUid: string): boolean {
  return tagUid.length > 0 && /[^0]/.test(tagUid);
}

// STUDIO-18344: resolve a `${ams_id}:${slot_id}` key against the latest AMS
// snapshot. Returns null when either the unit or the slot has disappeared
// since the user clicked (filament physically pulled, etc.) so callers can
// drop stale keys without crashing on a missing `.tray` access.
function lookupSelectedSlot(
  amsData: AmsData | null,
  key: string,
): { ams_id: string; slot_id: string; tray: AmsTray } | null {
  if (!amsData || !key) return null;
  const [amsId, slotId] = key.split(':');
  if (!amsId || !slotId) return null;
  const unit = amsData.ams_units.find((u) => u.ams_id === amsId);
  if (!unit) return null;
  const tray = unit.trays.find((t) => t.slot_id === slotId);
  if (!tray) return null;
  return { ams_id: amsId, slot_id: slotId, tray };
}

// STUDIO-17958: `<input type="number">` controlled by a numeric React state
// keeps a stale leading "0" once the controlled value has rendered "0".
// Sequence: user clears the field → Number("")||0 == 0 → React syncs DOM to
// "0" → next keystroke produces "08" → onChange parses Number("08") == 8 →
// React's controlled-input sync skips the DOM write because the parsed
// numeric value already matches → "08" stays visible and subsequent digits
// append as "080", "0800", etc. Strip the leading zeros from the literal
// string and write the canonical form back to the DOM input before updating
// state so the displayed text and React state stay in sync. Preserve a lone
// "0" and a "0." prefix so mid-typing decimals (e.g. "0.5") still work.
function sanitizeWeightInput(target: HTMLInputElement): number {
  const raw = target.value;
  if (raw.length > 1 && raw.startsWith('0') && !raw.startsWith('0.')) {
    const stripped = raw.replace(/^0+(?=\d)/, '');
    if (stripped !== raw) target.value = stripped;
    return Number(stripped) || 0;
  }
  return Number(raw) || 0;
}

function normalizePresetFilamentName(name: string | undefined, vendor: string, type: string, series: string): string {
  let value = (name || '').trim().replace(/\s+@.*$/, '');
  const fallback = formatTypeSeries(type, series);
  if (!value) return fallback;

  const aliases = [vendor, vendor.replace(/\s+/g, '')];
  if (vendor === 'Bambu Lab') aliases.push('Bambu');
  for (const alias of aliases.filter(Boolean)) {
    if (value === alias) return fallback;
    if (value.startsWith(`${alias} `)) {
      value = value.substring(alias.length + 1).trim();
      break;
    }
  }
  return value || fallback;
}

interface Props {
  open: boolean;
  editingSpool: Spool | null;        // null = add mode
  prefilledSpool: Partial<Spool> | null; // addSimilar prefill
  presets: PresetVendor[];
  onClose: () => void;
  onSubmitAdd: (data: Partial<Spool>, quantity: number) => boolean | Promise<boolean>;
  onSubmitUpdate: (data: Partial<Spool>) => boolean | Promise<boolean>;
  // STUDIO-18344: batch-add path for AMS multi-select. `creates[]` go through
  // the create dispatcher; `updates[]` carry an existing `spool_id` and go
  // through the update dispatcher (default UX for tag_uid collisions, per
  // the ticket's confirmation). Returns true when all items were enqueued
  // successfully on the C++ side; toast surface is handled by the bridge.
  onBatchCreate: (
    creates: Partial<Spool>[],
    updates: Partial<Spool>[],
  ) => boolean | Promise<boolean>;
  onFetchMachines: () => Promise<MachineItem[]>;
  // Ask the currently-selected (or specified) printer to resend its full
  // state package. Bound to the refresh button next to the Printer
  // dropdown. Read-only with respect to the globally selected machine.
  onRequestPushall: (devId?: string) => Promise<boolean>;
  // `switchSelected=true` signals a user-initiated machine switch from
  // this dialog; the C++ side will update Studio's global selected
  // machine. Poll ticks and read-only snapshot refreshes must omit this
  // flag so C++ does not repeatedly call set_selected_machine.
  onFetchAmsData: (devId?: string, switchSelected?: boolean) => Promise<AmsData | null>;
}

export function AddEditDialog({
  open, editingSpool, prefilledSpool, presets, onClose,
  onSubmitAdd, onSubmitUpdate, onBatchCreate,
  onFetchMachines, onRequestPushall, onFetchAmsData,
}: Props) {
  const { t } = useTranslation();
  const isEdit = !!editingSpool;
  const initSpool = editingSpool || prefilledSpool;

  // Pull cloud-side filament config so the brand dropdown includes vendors
  // the user has configured in the cloud but not yet locally.
  const cloudConfig = useStore((s) => s.filament.cloudConfig);
  const spools = useStore((s) => s.filament.spools);
  // F4.7: mirror of Studio's global selected machine. Used to default the
  // AMS-tab printer and to follow external changes made via
  // DeviceManager::OnSelectedMachineChanged.
  const globalSelectedDev = useStore((s) => s.filament.selectedMachineDevId);
  const mergedVendorNames = useMemo(() => {
    const cloudVendors = Array.isArray(cloudConfig?.vendors) ? cloudConfig.vendors : undefined;
    return buildVendorOptions(presets, cloudVendors, spools);
  }, [presets, cloudConfig, spools]);

  // Dialog mode
  const [mode, setMode] = useState<'manual' | 'ams'>('manual');

  // Form fields
  const [brand, setBrand] = useState('');
  const [materialType, setMaterialType] = useState('');
  const [series, setSeries] = useState('');
  const [colorCode, setColorCode] = useState('');
  const [customColors, setCustomColors] = useState<string[]>([]);
  const [colorName, setColorName] = useState('');
  // STUDIO-17977 / Task 10: gradient/multicolor support in the manual-add
  // path. Both fields mirror FilamentSpool.colors / .color_type (swagger
  // semantics: 0=gradient / 1=multicolor / 2=single). They stay in sync with
  // colorCode: picking a candidate from FilamentColorCodeQuery seeds all
  // four (color_code, colors[], color_type, color_name); picking a plain
  // custom hex via the "+" picker resets colors=[] and color_type=2 so the
  // outgoing spool is unambiguously single-colour.
  const [colors, setColors] = useState<string[]>([]);
  const [colorType, setColorType] = useState<0 | 1 | 2>(2);
  // STUDIO-17977 F1.3: BBL 官方耗材代码（如 "Q01B00" / "13903"），来自
  // FilamentColorCodeQuery 中匹配的 candidate。仅用于 form 当前会话内的
  // UI 展示（预览栏右侧），**不持久化**到 FilamentSpool / cloud schema：
  // 下次 dialog 打开时由 resolver effect 从 candidates cache 重新反查。
  // cache miss 或非官方耗材时为空字符串，UI 自动隐藏对应 span。
  const [filaColorCode, setFilaColorCode] = useState('');
  // STUDIO-17977 F1.3: tracks which fila_id the form's colour triple is
  // currently in sync with. Cleared on every dialog (re)open by the init
  // effect, then advanced by the colour-alignment effect. The first
  // observation per session is non-destructive (we trust whatever colour
  // is on the form); subsequent fila_id transitions trigger a reconcile
  // pass that snaps the colour to the new candidate palette when the
  // previous one is no longer valid for the new filament type.
  const alignedFilaIdRef = useRef<string>('');
  // STUDIO-17977 follow-up: tracks whether the user has performed a
  // colour-changing action since this dialog session opened (picked a
  // candidate / a custom swatch, confirmed the picker, or toggled an
  // AMS slot). Once true the alignment effect's "first observation"
  // exemption is dropped, so subsequent fila_id transitions reconcile
  // even if the form's earlier colour came from a non-official-brand
  // fallback panel that bypassed the strict per-fila_id route.
  const userTouchedColorRef = useRef<boolean>(false);
  // STUDIO-17977 follow-up (AMS slot toggle bug): selectAmsSlot writes the
  // tray's authoritative colour triple (color_code / colors / color_type /
  // color_name / fila_color_code) into the form, then bumps brand /
  // material_type / series — which in turn changes filaId.  The fila_id
  // reconcile effect below normally treats a fila_id transition that is
  // accompanied by `userTouchedColorRef === true` as "user manually
  // switched filament type, force-snap colour to the new palette's first
  // candidate".  That logic is wrong for AMS slot toggles: the AMS hex
  // (e.g. #5E43B7 紫 on a PLA Basic slot) is the *real* spool colour and
  // legitimately may not appear in the new fila_id's official candidate
  // list; the reconcile should NOT collapse it to candidates[0] (which
  // would surface as "黑色 / 10101 / #000000" regardless of the actual
  // tray hex).  This token marks the next fila_id transition as
  // AMS-driven so the reconcile effect aligns silently and skips the
  // snap-to-fallback branch.  Consumed exactly once.
  const amsSlotDrivenFilaIdSwapRef = useRef<boolean>(false);
  // STUDIO-17991: align the weight form with the cloud schema
  // (design-user.api CreateFilamentV2Req: netWeight + totalNetWeight only).
  // The legacy "Total - Spool = Net" three-column UI leaked spool_weight
  // even though the cloud never round-trips it, which let pull-push cycles
  // strip 料盘 and leave the Remain column denominator drifting to
  // 1250 / 1013 / 995. Keep the form in the cloud's net-weight domain
  // end to end: 当前净重 ↔ net_weight, 总净重 ↔ initial_weight.
  const [totalNetWeight, setTotalNetWeight] = useState(1000);
  const [currentNetWeight, setCurrentNetWeight] = useState(1000);
  const [note, setNote] = useState('');
  const [quantity, setQuantity] = useState(1);

  // AMS state
  const [machines, setMachines] = useState<MachineItem[]>([]);
  const [amsData, setAmsData] = useState<AmsData | null>(null);
  const [selectedUnit, setSelectedUnit] = useState<string | null>(null);
  // STUDIO-18344: multi-select slots. Each entry is `${ams_id}:${slot_id}`.
  // The live tray for each key is looked up from `amsData` on demand, so MQTT
  // refreshes propagate without needing to mirror tray snapshots into local
  // state. Single-select form behaviour is preserved by reseeding the form
  // whenever the set transitions to size 1 (see `useEffect` below).
  const [selectedSlotKeys, setSelectedSlotKeys] = useState<Set<string>>(() => new Set());
  // Track the slot that last seeded the editable form so we only call the
  // expensive `selectAmsSlot` field-resolver when the primary slot truly
  // changes (size 1 <-> 1 swap, or 0/N -> 1 transition). Size >= 2 leaves
  // this alone because the form is hidden.
  const lastSeededSlotKeyRef = useRef<string>('');
  const [amsLockedFields, setAmsLockedFields] = useState({
    brand: false,
    material: false,
    color: false,
    weight: false,
  });
  const [amsLoading, setAmsLoading] = useState(false);
  const [amsError, setAmsError] = useState('');
  const emptyAmsPollCountRef = useRef(0);
  // STUDIO-18344: shown above the slot grid in multi-select mode so the user
  // can see how many tag_uid hits will overwrite existing spools before
  // confirming the batch save. Derived in a useMemo below.

  // STUDIO-18385: pending duplicate-RFID overwrite confirmation. The AMS
  // save path (single + multi) writes to this state instead of dispatching
  // when an existing spool would be overwritten; the actual bridge call
  // is deferred to confirmRfidOverwrite() once the user accepts. The
  // payload snapshot captured here is what gets sent on confirm, so a
  // late AMS poll cannot mutate the wire data between the prompt and the
  // user's click.
  const [rfidConfirm, setRfidConfirm] = useState<
    | { kind: 'single'; existing: Spool; data: Partial<Spool> }
    | { kind: 'batch'; creates: Partial<Spool>[]; updates: Partial<Spool>[] }
    | null
  >(null);

  // Reset form when dialog opens
  useEffect(() => {
    if (!open) return;
    setMode('manual');
    setQuantity(1);
    setSelectedSlotKeys(new Set());
    lastSeededSlotKeyRef.current = '';
    setSelectedUnit(null);
    setAmsLockedFields({ brand: false, material: false, color: false, weight: false });
    setAmsData(null);
    setAmsError('');
    // STUDIO-17977 F1.3: forget the previous dialog session's fila_id so
    // the alignment effect treats this open as a fresh first observation
    // and does not snap colours that the parent just seeded via initSpool
    // or that we are about to seed for an 'add' flow.
    alignedFilaIdRef.current = '';
    // STUDIO-17977 follow-up: reset interaction tracker so the first
    // alignment after open is non-destructive (protects initSpool seed).
    userTouchedColorRef.current = false;
    // STUDIO-17977 follow-up (AMS slot toggle): drop any leftover token from
    // a prior dialog session so the very first reconcile pass after open
    // doesn't get silently aligned to whatever fila_id the form ends up at.
    amsSlotDrivenFilaIdSwapRef.current = false;
    // STUDIO-17977 F1.3: BBL 官方代码不持久化，每次 open 都从空开始；
    // 由 resolver effect 在 candidates 加载完后从 hit.color_code 反查回填。
    setFilaColorCode('');
    if (initSpool) {
      setBrand(initSpool.brand || '');
      setMaterialType(initSpool.material_type || '');
      setSeries(initSpool.series || '');
      const initialColor = normalizeColorCode(initSpool.color_code);
      setColorCode(initialColor);
      setCustomColors(initialColor && !isPresetColor(initialColor) ? [initialColor] : []);
      setColorName(initSpool.color_name || '');
      // Restore multicolor / gradient state (W4 added these to the wire
      // schema; W5 already round-trips them through the AMS read path).
      // Default color_type to 2 (single) when the legacy spool has no
      // explicit value so the outgoing payload stays valid.
      setColors(Array.isArray(initSpool.colors) ? [...initSpool.colors] : []);
      setColorType(((initSpool.color_type ?? 2) as 0 | 1 | 2));
      // Transparent migration from the legacy 毛重/料盘/净重 shape:
      // old rows stored initial_weight as 毛重 with spool_weight > 0,
      // new rows store initial_weight as the pure 整卷净重 with
      // spool_weight == 0. Collapsing "initial - spool" yields the
      // correct 整卷净重 in either case, and on save the row is rewritten
      // in the normalised shape so the next edit is already clean.
      const legacySpool = initSpool.spool_weight || 0;
      const netInit = Math.max(0, (initSpool.initial_weight || 0) - legacySpool);
      setTotalNetWeight(netInit > 0 ? netInit : 1000);
      const pct = initSpool.remain_percent || 0;
      const curNet = (typeof initSpool.net_weight === 'number' && initSpool.net_weight > 0)
        ? Math.round(initSpool.net_weight)
        : Math.round(netInit * pct / 100);
      setCurrentNetWeight(curNet > 0 ? curNet : (netInit > 0 ? netInit : 1000));
      setNote(initSpool.note || '');
    } else {
      setBrand(''); setMaterialType(''); setSeries('');
      setColorCode(''); setCustomColors([]); setColorName('');
      setColors([]); setColorType(2);
      setTotalNetWeight(1000); setCurrentNetWeight(1000);
      setNote('');
    }
    // STUDIO-17977 follow-up: depend on initSpool / prefilledSpool, not just
    // `open`. The same dialog instance is reused for "edit a spool" and
    // "add a fresh spool" - re-opening with a different `initSpool` (or
    // dropping it back to null) must reset the form, not preserve the
    // previous session's data. The earlier [open]-only deps relied on
    // open false→true, but that transition only happens between two
    // distinct close→open cycles, not when the parent flips initSpool
    // mid-session (e.g. detail → edit → cancel → add).
  }, [open, initSpool, prefilledSpool]);

  const findPresetMatchByFilamentId = useCallback((setting: {
    filamentVendor?: string;
    filamentType?: string;
    filamentId?: string;
  }) => {
    const vendorName = (setting.filamentVendor || '').trim();
    const typeName = (setting.filamentType || '').trim();
    const filamentId = (setting.filamentId || '').trim();
    if (!filamentId) return null;

    for (const vendor of presets) {
      if (vendorName && vendor.name !== vendorName) continue;
      for (const tp of vendor.types) {
        if (typeName && tp.name !== typeName) continue;
        const item = tp.items?.find((entry) => entry.setting_id === filamentId || entry.filament_id === filamentId);
        if (item) return { vendor, type: tp, item };
      }
    }
    return null;
  }, [presets]);

  const getCloudSettingDisplayName = useCallback((setting: {
    filamentVendor?: string;
    filamentType?: string;
    filamentName?: string;
    filamentId?: string;
  }) => {
    const cloudName = (setting.filamentName || '').trim();
    const idMatch = findPresetMatchByFilamentId(setting);
    if (idMatch) {
      return cloudName;
    }

    const match = (() => {
      for (const vendor of presets) {
        if (setting.filamentVendor && vendor.name !== setting.filamentVendor) continue;
        for (const tp of vendor.types) {
          if (setting.filamentType && tp.name !== setting.filamentType) continue;
          const item = tp.items?.find((entry) => {
            const presetName = normalizePresetFilamentName(entry.name, vendor.name, tp.name, entry.series || '');
            return !!cloudName && presetName === cloudName;
          });
          if (item) return { vendor, type: tp, item };
        }
      }
      return null;
    })();
    if (match) {
      return normalizePresetFilamentName(
        match.item.name,
        match.vendor.name,
        match.type.name,
        match.item.series || '',
      );
    }
    return cloudName;
  }, [findPresetMatchByFilamentId, presets]);

  // UX decision (per F4.3 feedback, revised):
  //   收起 Type / Series 两个独立字段，合并为单个「耗材类型」<select>，
  //   选项直接显示云端 `get_filament_config` 返回的 filamentName 完整名
  //   （例如 "PLA Basic" / "PETG Translucent" / "PLA-S Support For PLA/PETG"）。
  //   这样下拉值与云端创建/更新耗材接口的 filamentName 字段语义一致，不再
  //   依赖本地 preset 的 "type + series[]" 拼接。本地 preset 仅作为云端
  //   config 尚未拉回来时的 fallback 兜底。
  const typeSeriesOptions = useMemo<string[]>(() => {
    const set = new Set<string>();

    const settings = cloudConfig?.filamentSettings;
    if (Array.isArray(settings)) {
      settings.forEach((it) => {
        if (!it) return;
        if (brand && it.filamentVendor !== brand) return;
        const name = getCloudSettingDisplayName(it);
        if (name) set.add(name);
      });
    }

    if (set.size === 0) {
      const vendors = brand ? presets.filter((v) => v.name === brand) : presets;
      vendors.forEach((v) => {
        v.types.forEach((tp) => {
          if (Array.isArray(tp.items) && tp.items.length > 0) {
            tp.items.forEach((item) => {
              const name = normalizePresetFilamentName(item.name, v.name, tp.name, item.series || '');
              if (name) set.add(name);
            });
            return;
          }
          const series = Array.isArray(tp.series) ? tp.series.filter(Boolean) : [];
          if (series.length === 0) {
            if (tp.name) set.add(tp.name);
          } else {
            series.forEach((s) => set.add(formatTypeSeries(tp.name, s)));
          }
        });
      });
    }
    return [...set].sort();
  }, [brand, cloudConfig, presets, getCloudSettingDisplayName]);

  // Split a combined "PLA Basic" string back into (type, series) using the
  // vendor's known types as anchors (longest-first to tolerate types with
  // spaces). Falls back to first token as type / rest as series.
  const splitTypeSeries = (full: string): { type: string; series: string } => {
    const s = (full || '').trim();
    if (!s) return { type: '', series: '' };
    const allTypes = new Set<string>();
    const vendors = brand ? presets.filter((v) => v.name === brand) : presets;
    vendors.forEach((v) => v.types.forEach((tp) => { if (tp.name) allTypes.add(tp.name); }));
    const sortedTypes = [...allTypes].sort((a, b) => b.length - a.length);
    for (const tp of sortedTypes) {
      if (s === tp) return { type: tp, series: '' };
      if (s.startsWith(tp + ' ')) return { type: tp, series: s.substring(tp.length + 1).trim() };
    }
    const first = s.split(/\s+/)[0];
    return { type: first, series: s.substring(first.length).trim() };
  };

  // Material Type 下拉当前值 = 云端 filamentName（本地 series）。不再做 type+series
  // 前缀拼接；对于云端 filamentName = "Support For PA/PET" 且 filamentType = "PA"
  // 这类"series 不含 type 前缀"的情况，拼接会错渲染成 "PA Support For PA/PET"。
  // series 为空时退回到 material_type（覆盖仅有 type 无 series 的简单场景）。
  const typeSeriesFull = (series || '').trim() || (materialType || '').trim();

  // 云端 filamentSettings 里和当前 brand + series（filamentName）对上的那条记录，
  // 用于取权威的 filamentId 作为本地 setting_id（与云端 POST/PUT 的 filamentId 字段
  // 对齐，也便于下次 pull 回来时 preset 关联一致）。
  const matchedCloudFilamentId = useMemo(() => {
    const settings = cloudConfig?.filamentSettings;
    if (!Array.isArray(settings)) return '';
    const name = (series || '').trim();
    if (!name || !brand) return '';
    const hit = settings.find(
      (it) => it && it.filamentVendor === brand && getCloudSettingDisplayName(it) === name,
    );
    return (hit?.filamentId || '').trim();
  }, [cloudConfig, brand, series, getCloudSettingDisplayName]);

  // 语义统一：本地 series 直接对齐云端 filamentName 的完整名（如 "PLA Basic"）。
  // preset 里 items[].series 历史上是短名（"Basic"），因此比对时同时接受
  // 短名和完整名两种形态，保证新老数据都能匹配到 preset。
  const matchedPresetItem = useMemo(() => {
    for (const vendor of presets) {
      if (vendor.name !== brand) continue;
      for (const tp of vendor.types) {
        if (tp.name !== materialType) continue;
        const item = tp.items?.find((entry) => {
          const presetSeries = entry.series || '';
          const presetName = normalizePresetFilamentName(entry.name, vendor.name, tp.name, presetSeries);
          return presetSeries === (series || '')
              || presetName === (series || '')
              || formatTypeSeries(tp.name, presetSeries) === (series || '')
              || presetSeries === formatTypeSeries(tp.name, series);
        });
        if (item) return item;
      }
    }
    return null;
  }, [presets, brand, materialType, series]);

  // STUDIO-17977 / Task 10: drive the colour palette from
  // `filament.colors.query_for_id`. The same fila_id resolution as
  // handleSubmit (cloud filamentId > preset setting_id > preset filament_id)
  // is reused here so the candidate query keys off whatever the spool will
  // actually serialise as `setting_id` on save.
  const filaId = useMemo(
    () => (
      matchedCloudFilamentId
      || matchedPresetItem?.setting_id
      || matchedPresetItem?.filament_id
      || initSpool?.setting_id
      || ''
    ),
    [matchedCloudFilamentId, matchedPresetItem, initSpool?.setting_id],
  );
  const candidatesByFilaId = useStore((s) => s.filament.candidatesByFilaId);
  const setColorCandidates = useStore((s) => s.filament.setColorCandidates);
  // STUDIO-17977 F1.3: memoise the per-fila_id slice so downstream effects
  // (notably the colorName resolver) don't see a fresh `candidates` array
  // identity on every render and re-run pointlessly.
  const candidates: CandidateColor[] = useMemo(
    () => (filaId ? (candidatesByFilaId[filaId] ?? []) : []),
    [filaId, candidatesByFilaId],
  );

  // STUDIO-17977 follow-up requirement 3: when the user is editing a
  // *non-official* spool (custom brand / no preset match → empty filaId,
  // or filaId with no candidates), fall back to "all official colours of
  // the same material_type" by aggregating every preset item under any
  // vendor that exposes a type whose name matches `materialType`.
  // - The aggregation keeps `setting_id` of the originating fila_id
  //   *opaque*: picking from the fallback palette only seeds the colour
  //   triple; the spool's own setting_id is left untouched (Q3 =
  //   keep_setting_id), i.e. "borrow the colour, not the identity".
  // - Without a back-end RPC we rely on the existing per-fila_id RPC
  //   loader and prefetch each candidate fila_id below, then read from
  //   the same cache. It is fan-out heavy on first open (≈ Σ items
  //   under matching types) but the in-process bridge round-trip is
  //   cheap and the cache short-circuits subsequent opens.
  const fallbackFilaIds = useMemo<string[]>(() => {
    if (!materialType) return [];
    const ids = new Set<string>();
    for (const vendor of presets) {
      for (const tp of vendor.types) {
        if (tp.name !== materialType) continue;
        for (const item of tp.items || []) {
          const id = (item.setting_id || item.filament_id || '').trim();
          if (id) ids.add(id);
        }
      }
    }
    return [...ids];
  }, [presets, materialType]);

  // Final fallback when neither the per-fila_id RPC nor the type-aggregated
  // pool yields anything — e.g. a custom-brand spool whose user-created
  // PLA Basic preset has a setting_id that is not in the cloud catalogue,
  // so no FilamentColorCodeQuery row exists and no other vendor's PLA Basic
  // ids match either.  Surfacing the legacy BAMBU 40-hex palette here keeps
  // parity with the pre-STUDIO-17977 panel: the user can still pick a
  // colour, the chosen hex flows into spool.color_code with name='' and
  // color_type=2 (single colour), which is exactly the legacy semantics.
  const bambuFallbackCandidates = useMemo<CandidateColor[]>(
    () =>
      BAMBU_COLORS.map((hex): CandidateColor => {
        const code = hex.toUpperCase();
        return { color_code: code, colors: [code], color_type: 2, name: '' };
      }),
    [],
  );

  // The set actually rendered by the panel.  Composition rules:
  //
  //   Original layer (priority order, first non-empty wins):
  //     1. strict per-fila_id candidates (official BBL match)
  //     2. type-aggregated fallback (other vendors' same material_type)
  //     3. BAMBU 40-colour legacy palette (only after material is chosen,
  //        so dialog open does not flash a full palette before settling)
  //
  // Do not append colours from the user's inventory here. Manual material
  // switching and AMS slot switching both need a full palette replacement
  // based on the current brand/material context, not an accumulating list.
  const effectiveCandidates: CandidateColor[] = useMemo(() => {
    if (candidates.length > 0) {
      return candidates;
    }
    if (fallbackFilaIds.length > 0) {
      const out: CandidateColor[] = [];
      const seen = new Set<string>();
      for (const id of fallbackFilaIds) {
        const list = candidatesByFilaId[id];
        if (!list) continue;
        for (const c of list) {
          const key = `${c.color_type}|${(c.colors || []).join(',').toUpperCase()}`;
          if (seen.has(key)) continue;
          seen.add(key);
          out.push(c);
        }
      }
      if (out.length > 0) {
        return out;
      }
    }
    return materialType ? bambuFallbackCandidates : [];
  }, [
    candidates,
    fallbackFilaIds,
    candidatesByFilaId,
    materialType,
    bambuFallbackCandidates,
  ]);

  // STUDIO-17977 F1.3: derived preview-bar visuals.
  // - previewSwatchBackground delegates to the shared `cssBackgroundFor`
  //   so the 24×24 candidate / preview swatch / list row mini swatch /
  //   detail dialog swatch all share one rendering rule.  When the form's
  //   `colorType` is 2 / undefined but `colors[]` has 2+ hexes, the helper
  //   defaults to a smooth gradient so the visible hex list is honoured.
  // - previewHexLabel expands `colors[]` for non-single rows so the row
  //   carries every constituent hex, not just the primary.
  const previewSwatchBackground = useMemo(() => {
    return cssBackgroundFor({
      hexes: colors,
      primaryHex: colorCode,
      colorType,
    });
  }, [colors, colorType, colorCode]);

  const previewHexLabel = useMemo(() => {
    if (colors.length > 1) {
      return colors.map((c) => (c || '').toUpperCase()).filter(Boolean).join(' / ');
    }
    return (colorCode || '').toUpperCase();
  }, [colors, colorCode]);

  // Issue the JSON-RPC lazily and cache by fila_id. We read the cache via
  // `useStore.getState()` so the callback identity stays stable; otherwise
  // every cache mutation would change the deps of the loader and re-trigger
  // the effect, defeating the cache. The empty-array fallback on failure
  // doubles as a negative cache so a transient C++ error doesn't make the
  // dialog spam the dispatcher on every state tick.
  const requestRpc = useDeviceBridge();
  const loadCandidates = useCallback(async (id: string) => {
    if (!id) return;
    const cur = useStore.getState().filament.candidatesByFilaId;
    if (cur[id]) return;
    try {
      const res = await requestRpc<{
        module: 'filament'; submod: 'colors'; action: 'query_for_id';
        payload: { fila_id: string };
      }, BridgeResponseBody>({
        module: 'filament', submod: 'colors', action: 'query_for_id',
        payload: { fila_id: id },
      });
      if (res.ok && res.value.error_code === 0) {
        const payload = res.value.payload as unknown as FilamentColorCodesResponse;
        const list = Array.isArray(payload?.candidates) ? payload.candidates : [];
        // STUDIO-17977: don't clobber a populated cache entry with an empty
        // list. Mirrors the prefetch guard in useFilamentManagerBridge: if a
        // concurrent loader (the bridge prefetch fired by spools change)
        // already wrote a non-empty candidate list and a slow / momentarily
        // failing RPC lands here later with an empty payload, keep the good
        // list. Otherwise the row tail would briefly show colorName, then
        // lose it as the empty response races in (the user-visible "瞬间有
        // 颜色名称，但很快变成不正确" symptom).
        const after = useStore.getState().filament.candidatesByFilaId[id];
        if (list.length === 0 && Array.isArray(after) && after.length > 0) return;
        setColorCandidates(id, list);
      } else {
        const why = res.ok ? res.value.message : res.error;
        console.warn('[fila] loadColorCandidates failed for', id, why);
        // Don't overwrite a non-empty cache with an empty negative entry on
        // a transient C++ error, same reason as the success path.
        const after = useStore.getState().filament.candidatesByFilaId[id];
        if (Array.isArray(after) && after.length > 0) return;
        setColorCandidates(id, []);
      }
    } catch (err) {
      console.warn('[fila] loadColorCandidates threw for', id, err);
      const after = useStore.getState().filament.candidatesByFilaId[id];
      if (Array.isArray(after) && after.length > 0) return;
      setColorCandidates(id, []);
    }
  }, [requestRpc, setColorCandidates]);

  useEffect(() => {
    if (!open || !filaId) return;
    void loadCandidates(filaId);
  }, [open, filaId, loadCandidates]);

  // STUDIO-17977 follow-up requirement 3: prefetch every fila_id whose
  // material_type matches the current form selection so the type-aggregated
  // fallback panel has data to render. Fires only when the strict per-
  // fila_id panel would otherwise be empty (no filaId, or filaId resolved
  // but its cached entry is empty). The loader is idempotent (cache-checked
  // inside), so this is safe to fire on every dependency change.
  useEffect(() => {
    if (!open) return;
    const primaryHasData = !!filaId && (candidatesByFilaId[filaId]?.length ?? 0) > 0;
    if (primaryHasData) return;
    if (fallbackFilaIds.length === 0) return;
    for (const id of fallbackFilaIds) {
      if (id === filaId) continue;
      void loadCandidates(id);
    }
  }, [open, filaId, fallbackFilaIds, candidatesByFilaId, loadCandidates]);

  // Comparing the form's current selection against a candidate. Delegates
  // to `candidateMatchesFormState` from the shared `colors/` module so the
  // same semantics power list-row reverse lookup (resolveCandidateForSpool)
  // and dialog highlight here.  See `candidate.ts` for the full rule
  // explanation (multiset over `colors[]`, ignores `color_type` mismatches
  // between AMS RFID / BBL preset registry).
  const isCandidateSelected = useCallback((c: CandidateColor): boolean => {
    return candidateMatchesFormState({
      candidate: c,
      formColorCode: colorCode,
      formColors: colors,
    });
  }, [colorCode, colors]);

  // STUDIO-17977 F1.3: when the user switches to a different filament
  // type (品牌 / 类型 / series toggle), the candidate palette behind
  // `filaId` changes but the colour triple already on the form (color_code
  // / colors / color_type) was inherited from the previous palette. Snap
  // the form to the new palette so the displayed swatch + hex always
  // stay valid for the currently chosen filament type.
  //
  // Rules:
  //   - The first time a fila_id is observed in this dialog session is
  //     non-destructive (alignedFilaIdRef gets bumped from '' to filaId
  //     without touching the form). This protects:
  //       * initSpool round-trip on edit (parent already paired
  //         color_code with the right setting_id when the spool was
  //         saved, so the colour is by definition valid),
  //       * AMS slot toggles, where selectAmsSlot pre-seeds the new
  //         tray's colour explicitly, and
  //       * the freshly opened add-mode form, where colorCode is empty
  //         and there is nothing to reconcile yet.
  //   - Any subsequent fila_id transition reconciles. If the current
  //     colour matches a candidate in the new palette (single-colour by
  //     hex, gradient/multicolor by full colors[] + color_type) we keep
  //     it. Otherwise we snap to the new palette's first single-colour
  //     candidate (or candidates[0] when there is no single-colour entry)
  //     and let the resolver effect below fill in color_name from the
  //     same candidate.
  //   - While candidates are still loading we early-return without
  //     advancing alignedFilaIdRef, so a fila_id transition will not be
  //     "consumed" before the new palette is actually known.
  useEffect(() => {
    if (!filaId) return;
    if (!candidates || candidates.length === 0) return;

    // First-observation exemption: dialog just opened *and* the user has
    // not changed any colour yet → keep whatever initSpool / parent
    // seeded (this is the "edit existing spool" path). The exemption
    // expires the moment the user touches a candidate / custom swatch /
    // AMS slot, so a fila_id transition that follows e.g. a fallback-
    // panel pick (non-official brand) still reconciles correctly.
    if (!alignedFilaIdRef.current && !userTouchedColorRef.current) {
      alignedFilaIdRef.current = filaId;
      return;
    }
    if (alignedFilaIdRef.current === filaId) return;

    // AMS slot toggle pre-wrote the tray's authoritative colour triple for
    // the new fila_id; align silently and never overwrite the form.  The
    // tray hex may be a custom / 3rd-party colour absent from the official
    // candidate list, so the snap-to-fallback below would corrupt it.
    if (amsSlotDrivenFilaIdSwapRef.current) {
      alignedFilaIdRef.current = filaId;
      amsSlotDrivenFilaIdSwapRef.current = false;
      return;
    }

    const stillValid = !!colorCode && candidates.some((c) => isCandidateSelected(c));
    if (!stillValid) {
      const fallback = candidates.find((c) => c.color_type === 2) || candidates[0];
      if (fallback) {
        // fallback.color_code is the BBL official code (e.g. "Q01B00"),
        // not a hex - the primary hex always lives at fallback.colors[0].
        const primary = (fallback.colors && fallback.colors[0]) || '';
        if (primary) setColorCode(primary);
        setColors(Array.isArray(fallback.colors) ? [...fallback.colors] : []);
        setColorType((fallback.color_type ?? 2) as 0 | 1 | 2);
        setColorName(fallback.name || '');
        setFilaColorCode(fallback.color_code || '');
        // Clear stale custom-swatch selection that no longer applies to
        // the new palette; the user can re-pick if they want.
        setCustomColors([]);
      }
    }
    alignedFilaIdRef.current = filaId;
  }, [filaId, candidates, colorCode, isCandidateSelected]);

  // STUDIO-17977 F1.3: upgrade `colorName` to the canonical
  // FilamentColorCodeQuery candidate name when the form's colour triple
  // (color_code / colors / color_type) matches one. Resolver semantics:
  //   - AMS slot toggle: selectAmsSlot pre-clears colorName to '' so the
  //     stale name from the previous slot cannot leak through; this
  //     effect then fills in the new slot's canonical name once the
  //     candidates for the new fila_id finish loading.
  //   - onPickCandidate: writes c.name optimistically; the resolver
  //     re-confirms by finding the same candidate.
  //   - Free picker / custom-swatch: clear colorName to '' on commit;
  //     this resolver promotes it to a canonical name *only if* the hex
  //     coincides with an existing single-colour candidate.
  //   - Editing an existing spool: initSpool.color_name (C++ side has
  //     already done its own GetFilaColorName lookup) seeds colorName.
  //     We do NOT overwrite it when the front-end candidate cache cannot
  //     resolve a match - the C++ resolution is just as authoritative
  //     and the cache may simply be stale, empty for an unknown setting,
  //     or use slightly different hex normalisation.
  // Net rule: the resolver only writes when it has a real match; it
  // never erases a name that is already on the form.
  useEffect(() => {
    if (!colorCode) return;
    if (!candidates || candidates.length === 0) return;
    const hit = candidates.find((c) => isCandidateSelected(c));
    if (!hit) return;
    if (hit.name) {
      setColorName((prev) => (prev === hit.name ? prev : hit.name));
    }
    // STUDIO-17977 F1.3: BBL official colour code follows the same
    // write-only-on-hit rule as colorName - never erase a value already on
    // the form, so cache misses on edits don't blow away an optimistically
    // seeded code, and only update when we have a candidate match.
    if (hit.color_code) {
      setFilaColorCode((prev) => (prev === hit.color_code ? prev : hit.color_code));
    }
  }, [colorCode, colors, colorType, candidates, isCandidateSelected]);

  // Picking a query-driven candidate seeds *all four* form fields so the
  // outgoing spool round-trips through cloud POST + AMS sync as gradient /
  // multicolor. For single-colour candidates `colors` is left as a
  // single-element array — handleSubmit drops it back to undefined later so
  // the wire payload stays minimal for plain spools.
  const onPickCandidate = useCallback((c: CandidateColor) => {
    const primary = (c.colors && c.colors[0]) || '';
    if (primary) setColorCode(primary);
    setColors(Array.isArray(c.colors) ? [...c.colors] : []);
    setColorType(c.color_type);
    setColorName(c.name || '');
    // STUDIO-17977 F1.3: capture the BBL official colour code (e.g. "Q01B00"
    // / "13903") so the preview row can surface it next to the hex.
    //
    // BAMBU legacy fallback and user-owned supplemental candidates carry the
    // primary hex in `color_code` purely as a unique key (testid / dedup);
    // those values aren't real BBL codes, so we suppress them here and leave
    // the preview row's `preview-fila-code` slot empty — matching the legacy
    // pre-STUDIO-17977 behaviour for custom-brand spools.
    const looksLikeBblCode = !!c.color_code && !c.color_code.startsWith('#');
    setFilaColorCode(looksLikeBblCode ? c.color_code : '');
    userTouchedColorRef.current = true;
  }, []);

  // Picking an existing custom-colour swatch is always a single-colour
  // selection: clear any previous gradient / multicolor state so the spool
  // we save matches what the swatch visually represents.
  const onPickCustomSwatch = useCallback((hex: string) => {
    setColorCode(hex);
    setColors([]);
    setColorType(2);
    // STUDIO-17977 F1.3: a custom-swatch pick has no FilamentColorCodeQuery
    // name; clear color_name and the BBL official colour code so the
    // preview row hides them. Resolver effect promotes both back if the
    // hex happens to coincide with an existing single-colour candidate.
    setColorName('');
    setFilaColorCode('');
    userTouchedColorRef.current = true;
  }, []);

  // 下拉切换时：
  //  - series 直接存下拉选中的完整 filamentName（例如 "PLA Basic"）。这与
  //    云端 PUT/POST 的 filamentName 字段语义一致，避免本地短名上云后丢类型前缀。
  //  - material_type 优先从云端 filamentSettings 查该 filamentName 对应的
  //    filamentType（云端是权威来源，能覆盖形如 "PLA-S Support For PLA/PETG"
  //    这种本地 anchor 匹配会误切的复杂名称）。云端没命中再退回本地 preset
  //    的前缀 anchor 匹配。
  const handleTypeSeriesChange = (full: string) => {
    const name = (full || '').trim();
    let type = '';
    const settings = cloudConfig?.filamentSettings;
    if (Array.isArray(settings)) {
      const hit = settings.find(
        (it) => it && it.filamentVendor === brand && getCloudSettingDisplayName(it) === name,
      );
      if (hit) type = (hit.filamentType || '').trim();
    }
    if (!type) {
      outer: for (const vendor of presets) {
        if (brand && vendor.name !== brand) continue;
        for (const tp of vendor.types) {
          const hit = tp.items?.find((item) => {
            const itemName = normalizePresetFilamentName(item.name, vendor.name, tp.name, item.series || '');
            return itemName === name;
          });
          if (hit) {
            type = tp.name;
            break outer;
          }
        }
      }
    }
    if (!type) {
      const res = splitTypeSeries(name);
      type = res.type;
    }
    setMaterialType(type);
    setSeries(name);
  };

  // F4.5: validation no longer depends on `series` — the combined type field
  // covers both, and plenty of materials legitimately have no series (e.g. ABS).
  // Weight rule: both values must be positive and 当前 ≤ 总 so the derived
  // remain_percent never goes negative / > 100.
  // STUDIO-17959: also enforce a max cap on both fields so users can't submit
  // values that the backend silently clamps to 0.
  const weightError = (() => {
    if (totalNetWeight <= 0) return '';
    if (totalNetWeight > MAX_NET_WEIGHT_GRAMS || currentNetWeight > MAX_NET_WEIGHT_GRAMS) {
      return t('Weight cannot exceed {{max}}g', { max: MAX_NET_WEIGHT_GRAMS });
    }
    if (currentNetWeight > totalNetWeight) {
      return t('Current Net Weight cannot exceed Total Net Weight');
    }
    return '';
  })();
  // STUDIO-18344: in AMS multi-select mode the editable form is hidden, so
  // the per-field validation above is irrelevant — every payload is built
  // directly from the AMS tray. The form's `isValid` guard is therefore
  // skipped and we only require at least one slot to be selected.
  const isAmsBatch = !isEdit && mode === 'ams' && selectedSlotKeys.size >= 2;
  const isValid = isAmsBatch
    ? selectedSlotKeys.size >= 2
    : !!(
        brand && materialType && colorCode &&
        totalNetWeight > 0 && currentNetWeight >= 0 &&
        totalNetWeight <= MAX_NET_WEIGHT_GRAMS &&
        currentNetWeight <= MAX_NET_WEIGHT_GRAMS &&
        currentNetWeight <= totalNetWeight
      );

  // STUDIO-17977 F1.3: the previous F4.4 isCustomColor flag relied on a
  // BAMBU_COLORS hex-membership check, which became stale once the palette
  // switched to FilamentColorCodeQuery candidates. The "preset vs custom"
  // distinction now lives in the preview row directly: it shows color_name
  // when we have one (set by onPickCandidate from c.name) and falls back to
  // the "Custom Color" label otherwise. No standalone flag is needed.

  // STUDIO-18114: the custom color picker now uses a draft-then-commit flow.
  // Previously a hidden <input type="color"> committed every onChange tick,
  // which the native picker fires while the user is still dragging the hue
  // slider. That overwrote the form's color_code (and dirtied customColors)
  // long before the user actually decided on a color.
  // Now the popover holds a local `draftColor`; only OK calls
  // commitCustomColorSelection() to write it back to the form. Cancel and
  // ESC discard the draft. Outside clicks intentionally keep the popover open
  // so users do not lose a selected custom color by clicking blank space.
  const [colorPickerOpen, setColorPickerOpen] = useState(false);
  const [draftColor, setDraftColor] = useState('#000000');
  const colorPickerRef = useRef<HTMLDivElement>(null);
  const nativeColorInputRef = useRef<HTMLInputElement>(null);

  // The trigger button is rendered with `disabled={lockColor}` so a locked
  // AMS color cannot start a draft session in the first place; we therefore
  // don't need to re-check lockColor here.
  const openColorPicker = useCallback(() => {
    setDraftColor(colorCode || '#000000');
    setColorPickerOpen(true);
  }, [colorCode]);

  const cancelCustomColor = useCallback(() => {
    setColorPickerOpen(false);
  }, []);

  const confirmCustomColor = useCallback(() => {
    const next = commitCustomColorSelection(draftColor, customColors, BAMBU_COLORS);
    setColorCode(next.colorCode);
    setCustomColors(next.customColors);
    // Custom-picker is single-colour only: drop any prior gradient /
    // multicolor selection so the saved spool matches the swatch the user
    // just confirmed.
    setColors([]);
    setColorType(2);
    // STUDIO-17977 F1.3: a freshly hand-picked colour has no preset name
    // or BBL official code; clear both so the preview row reflects the
    // free-picker selection. Resolver effect upgrades them back if the
    // hex happens to coincide with a single-colour candidate.
    setColorName('');
    setFilaColorCode('');
    userTouchedColorRef.current = true;
    setColorPickerOpen(false);
  }, [draftColor, customColors]);

  // Esc key is treated as Cancel; outside clicks do not dismiss the picker
  // because that made the chosen color disappear before users could confirm.
  useEffect(() => {
    if (!colorPickerOpen) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.stopPropagation();
        cancelCustomColor();
      }
    };
    window.addEventListener('keydown', onKey, true);
    return () => {
      window.removeEventListener('keydown', onKey, true);
    };
  }, [colorPickerOpen, cancelCustomColor]);

  const handleSubmit = async () => {
    // STUDIO-18344: AMS multi-select fast path. When the user has ticked
    // two or more slots, the editable form is hidden (see the AMS pane
    // below) and we build each spool's payload straight from its live
    // tray via `buildSpoolFromTray`. Hits against an existing spool (by
    // tag_uid) become `updates[]` so the existing cloud record is
    // overwritten in place rather than duplicated (per ticket UX choice).
    //
    // The single-slot AMS path keeps the editable form and the existing
    // submit logic below, so this branch only fires when size >= 2.
    if (!isEdit && mode === 'ams' && selectedSlotKeys.size >= 2) {
      const devId = amsData?.selected_dev_id || '';
      const built = [] as ReturnType<typeof buildSpoolFromTray>[];
      // Iterate amsData top-down (units in order, slots in order) so the
      // batch result is stable and matches the visual order of the grid;
      // skip any selected key whose tray has since disappeared so a stale
      // selection cannot poison the wire payload.
      for (const unit of amsData?.ams_units || []) {
        for (const tray of unit.trays) {
          if (!tray.is_exists) continue;
          const key = `${unit.ams_id}:${tray.slot_id}`;
          if (!selectedSlotKeys.has(key)) continue;
          built.push(buildSpoolFromTray({ tray, unit, devId, presets, spools }));
        }
      }
      if (built.length === 0) {
        onClose();
        return;
      }
      const { creates, updates } = partitionTraysForBatchCreate(built);
      // STUDIO-18385: require explicit confirmation before overwriting any
      // existing spool records. Snapshot the partition so a late AMS poll
      // cannot mutate what gets sent on accept.
      if (updates.length > 0) {
        setRfidConfirm({ kind: 'batch', creates, updates });
        return;
      }
      const ok = await onBatchCreate(creates, updates);
      if (!ok) return;
      onClose();
      return;
    }

    // New weight model: initial_weight is now 整卷净重 (= swagger
    // totalNetWeight) and spool_weight is always persisted as 0 so no
    // code path can re-introduce 毛重 via cloud round-trips. remain_percent
    // is recomputed from 当前净重 / 总净重 so the three weight-related
    // fields (net_weight, initial_weight, remain_percent) are always
    // consistent on write.
    const remainPct = totalNetWeight > 0
      ? Math.min(100, Math.max(0, Math.round(currentNetWeight * 100 / totalNetWeight)))
      : 0;
    const data: Partial<Spool> = {
      brand, material_type: materialType, series,
      color_code: colorCode, color_name: colorName,
      initial_weight: totalNetWeight,
      spool_weight: 0,
      net_weight: currentNetWeight,
      remain_percent: remainPct,
      note,
      setting_id: matchedCloudFilamentId
        || matchedPresetItem?.setting_id
        || matchedPresetItem?.filament_id
        || initSpool?.setting_id
        || '',
    };

    // STUDIO-18340: emit `colors: []` for single-colour edits so an AMS-read
    // multicolor palette can be explicitly cleared when the user changes the
    // spool into a third-party single-colour filament.
    if (Array.isArray(colors) && colors.length > 1) {
      data.colors = [...colors];
      data.color_type = colorType;
    } else {
      data.colors = [];
      data.color_type = 2;
    }

    if (isEdit) {
      // STUDIO-17964: 编辑保存时只提交用户此次真正改过的字段。
      // - 空 patch 提交到 C++ 侧会被安全地忽略（不发空 PUT）。
      // - 与 initSpool 对齐未变的字段一律跳过；数字字段用 Object.is 比较避免
      //   NaN / +0 / -0 的歧义；字符串字段用 normalizeStr 把 null/undefined 视为
      //   空串，避免"本来就没有值"被误报成"改成了空"。
      const orig = editingSpool!;
      const normalizeStr = (v: unknown) =>
        (v === undefined || v === null) ? '' : String(v);
      const patch: Partial<Spool> = { spool_id: orig.spool_id };
      const patchFields = patch as Partial<Record<keyof Spool, Spool[keyof Spool]>>;
      (Object.keys(data) as (keyof Spool)[]).forEach((k) => {
        const nv = data[k];
        const ov = orig[k];
        let changed: boolean;
        if (Array.isArray(nv) || Array.isArray(ov)) {
          const na = Array.isArray(nv) ? nv : [];
          const oa = Array.isArray(ov) ? ov : [];
          changed = na.length !== oa.length || na.some((v, i) => v !== oa[i]);
        } else if (typeof nv === 'string' || typeof ov === 'string') {
          changed = normalizeStr(nv) !== normalizeStr(ov);
        } else {
          changed = !Object.is(nv, ov);
        }
        if (changed) patchFields[k] = nv;
      });
      const ok = await onSubmitUpdate(patch);
      if (!ok) return;
    } else {
      let amsExistingSpoolId = '';
      // STUDIO-18344: derived primary slot for the single-select AMS form
      // path. Only set when exactly one slot is selected, otherwise the
      // multi-select fast path above already returned.
      const primarySlot = (mode === 'ams' && selectedSlotKeys.size === 1)
        ? lookupSelectedSlot(amsData, [...selectedSlotKeys][0])
        : null;
      if (mode === 'ams' && primarySlot) {
        // The spool is imported from a live AMS slot. Propagate the
        // authoritative AMS-only fields (tag_uid / setting_id / diameter
        // / remain / binding) so the local record knows which physical
        // slot it came from. Weights come from the form state the user
        // confirmed (already baked into `data` above) but we override
        // `initial_weight` with the tray's reported 整卷净重 and
        // `remain_percent` with the authoritative device value so the
        // record lines up with what the printer reports on MQTT.
        const tray = primarySlot.tray;
        const rawTrayTagUid = tray.tag_uid || '';
        const trayTagUid = hasCloudRfid(rawTrayTagUid) ? rawTrayTagUid : '';
        const existingSpool = hasCloudRfid(trayTagUid)
          ? spools.find((sp) => (sp.tag_uid || '') === trayTagUid)
          : undefined;
        const trayNetInit = parseInt(String(tray.weight ?? '0'), 10) || 0;
        const remain = typeof tray.remain === 'number' ? tray.remain : 0;
        if (existingSpool?.spool_id) {
          amsExistingSpoolId = existingSpool.spool_id;
          data.spool_id = existingSpool.spool_id;
        }
        data.entry_method = 'ams_sync';
        data.tag_uid = trayTagUid;
        data.tray_id_name = tray.tray_id_name || '';
        // Keep the user's edited material choice. The AMS tray setting_id is
        // only a fallback when the form could not resolve a selected preset.
        data.setting_id = data.setting_id || tray.setting_id || '';
        data.bound_ams_id = primarySlot.ams_id;
        data.bound_dev_id = amsData?.selected_dev_id || '';
        data.remain_percent = remain;
        // STUDIO-17977: keep gradient/multicolor info when creating a spool
        // from an AMS slot. tray.colors / tray.color_type come from
        // FilamentManagerVM::build_ams_data (mirrors AMSColorMode on the device);
        // forwarding them here means the new FilamentSpool stays multicolor
        // instead of being silently downgraded to a single-color row. The
        // C++ FilamentSpool::from_json enforces the
        // `color_code == colors[0]` invariant on receipt, so we don't need
        // to special-case it here.
        //
        // Two normalisations mirror selectAmsSlot so the wire payload, the
        // form state, and the resulting list row stay byte-identical:
        //   1. Each hex in tray.colors goes through normalizeColorCode so
        //      MQTT-style raw "RRGGBBAA" / no-leading-# values become a
        //      canonical "#RRGGBB" before reaching FilamentSpool::from_json.
        //   2. When the device omits color_type for a multi-hex tray (MQTT
        //      `cols` present but no `ctype`) we default to gradient (0).
        //      Defaulting to single (2) here used to silently downgrade
        //      multicolor AMS slots to a single-colour row on the next
        //      cloud round-trip even though the form preview rendered them
        //      as gradient.
        const normalizedTrayColors = Array.isArray(tray.colors)
          ? tray.colors
              .map((c) => normalizeColorCode(c))
              .filter((c) => c.length > 0)
          : [];
        if (normalizedTrayColors.length > 0) {
          data.colors = normalizedTrayColors;
        }
        data.color_type = (typeof tray.color_type === 'number')
          ? tray.color_type
          : (normalizedTrayColors.length > 1 ? 0 : 2);
        if (trayNetInit > 0) {
          // tray.weight is already the spool's 整卷净重 (MQTT `tray_weight`,
          // see DevFilaSystem::weight); store it verbatim — no料盘 fudge.
          data.initial_weight = trayNetInit;
        }
        // `tray.diameter` is a string in the MQTT payload; accept both.
        const diaRaw = tray.diameter;
        const diaNum = typeof diaRaw === 'number' ? diaRaw : parseFloat(String(diaRaw ?? '0'));
        if (diaNum > 0) data.diameter = diaNum;
      } else {
        data.entry_method = 'manual';
      }
      // STUDIO-18385: AMS RFID matches an existing local record — gate the
      // overwrite behind an explicit confirmation. Snapshot `data` so a
      // late AMS poll cannot rewrite what we send on accept.
      if (amsExistingSpoolId) {
        const existing = spools.find((sp) => sp.spool_id === amsExistingSpoolId);
        if (existing) {
          setRfidConfirm({ kind: 'single', existing, data: { ...data } });
          return;
        }
      }
      const ok = amsExistingSpoolId
        ? await onSubmitUpdate(data)
        : await onSubmitAdd(data, mode === 'ams' ? 1 : quantity);
      if (!ok) return;
    }
    onClose();
  };

  // STUDIO-18385: dispatch the deferred AMS save once the user accepts the
  // duplicate-RFID overwrite. Single-select hits the update bridge; batch
  // forwards the captured creates/updates partition to the batch_create
  // bridge so creates and updates ride one transaction. Fail without
  // closing the dialog so the user can retry/edit; success closes as
  // usual.
  const confirmRfidOverwrite = useCallback(async () => {
    const pending = rfidConfirm;
    if (!pending) return;
    setRfidConfirm(null);
    if (pending.kind === 'single') {
      const ok = await onSubmitUpdate(pending.data);
      if (!ok) return;
    } else {
      const ok = await onBatchCreate(pending.creates, pending.updates);
      if (!ok) return;
    }
    onClose();
  }, [rfidConfirm, onSubmitUpdate, onBatchCreate, onClose]);

  // STUDIO-18385: derive the duplicate-RFID prompt copy from the pending
  // overwrite snapshot so the wording stays in sync with which spool / how
  // many slots the user is about to overwrite. Single-select names the
  // exact existing record (so the user can spot a wrong-printer mismatch);
  // batch reports the K-of-N hit count so the user knows how many cloud
  // rows will change.
  const rfidConfirmContent = useMemo(() => {
    if (!rfidConfirm) return null;
    if (rfidConfirm.kind === 'single') {
      const sp = rfidConfirm.existing;
      const label = [sp.brand, sp.material_type, sp.series, sp.color_name]
        .map((s) => (s || '').trim())
        .filter((s) => s.length > 0)
        .join(' · ') || sp.spool_id;
      return {
        title: t('Duplicate RFID detected'),
        message: t(
          'This RFID is already bound to "{{name}}". Continuing will overwrite the existing record with the latest AMS data. Proceed?',
          { name: label }
        ),
        confirmText: t('Overwrite'),
      };
    }
    const totalCount = rfidConfirm.creates.length + rfidConfirm.updates.length;
    const updateCount = rfidConfirm.updates.length;
    return {
      title: t('Duplicate RFID detected'),
      message: t(
        '{{updateCount}} of {{totalCount}} selected slots already have records and will be overwritten with the latest AMS data. Proceed?',
        { updateCount, totalCount }
      ),
      confirmText: t('Overwrite'),
    };
  }, [rfidConfirm, t]);

  // AMS mode switch
  const switchToAms = async () => {
    setMode('ams');
    setSelectedSlotKeys(new Set());
    lastSeededSlotKeyRef.current = '';
    setAmsLoading(true);
    setAmsError('');
    try {
      const list = await onFetchMachines();
      setMachines(list);
      if (list.length === 0) {
        setAmsData(null);
        setSelectedUnit(null);
        setSelectedSlotKeys(new Set());
        lastSeededSlotKeyRef.current = '';
        setAmsError('');
        setAmsLoading(false);
        return;
      }
      // F4.7: default to whichever printer Studio is globally pointing at
      // (DeviceManager::get_selected_machine), falling back to the first
      // online / first machine only when the global selection is not in
      // this printer list.
      const defaultDev =
        list.find((m) => globalSelectedDev && m.dev_id === globalSelectedDev) ||
        list.find((m) => m.is_online) ||
        list[0];
      // If the default machine already matches Studio's globally selected
      // machine, skip the set and just read that machine's AMS snapshot.
      // Only when we fall back to "first online / first in the list" do
      // we ask C++ to switch once so the tray list is not empty. This is
      // a one-shot soft switch at dialog open, not a recurring trigger.
      const needSwitch = !globalSelectedDev || defaultDev.dev_id !== globalSelectedDev;
      const data = await onFetchAmsData(defaultDev.dev_id, needSwitch);
      setAmsData(data);
      if (data && data.ams_units.length > 0) {
        setSelectedUnit(data.ams_units[0].ams_id);
      } else {
        emptyAmsPollCountRef.current = 0;
        setAmsError(t('Fetching AMS data…'));
      }
    } catch {
      setAmsError(t('Getting device list failed, please retry'));
    }
    setAmsLoading(false);
  };

  // switchSelected=true : user picked a different printer in the dropdown.
  //   This is the only path that should make C++ call
  //   DeviceManager::set_selected_machine.
  // switchSelected=false : mirror of an external Studio-wide machine
  //   switch. C++ has already been switched by OnSelectedMachineChanged,
  //   so we just reset the local selection state and re-read the latest
  //   AMS snapshot without asking C++ to switch again.
  const handleDeviceChange = useCallback(async (
    devId: string,
    switchSelected: boolean = true,
  ) => {
    setSelectedUnit(null);
    // STUDIO-18344: device switch clears all multi-select state. Slots on a
    // different printer are a different context and the AMS unit / slot
    // index numbering may collide; carrying the selection over would risk
    // submitting trays the user can no longer see in the new device's grid.
    setSelectedSlotKeys(new Set());
    lastSeededSlotKeyRef.current = '';
    setAmsLoading(true);
    setAmsError('');
    try {
      const data = await onFetchAmsData(switchSelected ? devId : undefined, switchSelected);
      setAmsData(data);
      if (data && data.ams_units.length > 0) {
        setSelectedUnit(data.ams_units[0].ams_id);
      } else {
        emptyAmsPollCountRef.current = 0;
        setAmsError(t('Fetching AMS data…'));
      }
    } catch {
      setAmsError(t('Getting AMS data failed'));
    }
    setAmsLoading(false);
  }, [onFetchAmsData, t]);

  // Refresh button next to the Printer dropdown. Asks the selected
  // printer to resend its full state (get_version + pushall) so the AMS
  // tray snapshot in this dialog converges immediately instead of
  // waiting for the next spontaneous push from the device. Throttled for
  // ~2s to avoid hammering the printer on rapid double-clicks; the
  // button stays disabled while the throttle window is active.
  const [refreshBusy, setRefreshBusy] = useState(false);
  const handleRequestPushall = useCallback(async () => {
    if (refreshBusy) return;
    const devId = amsData?.selected_dev_id
      || machines.find((m) => m.is_online)?.dev_id
      || machines[0]?.dev_id
      || '';
    if (!devId) return;
    setRefreshBusy(true);
    emptyAmsPollCountRef.current = 0;
    setAmsError(t('Fetching AMS data…'));
    try {
      await onRequestPushall(devId);
    } catch {
      // non-fatal: the next AMS poll tick will still pick up whatever
      // the printer eventually pushes back on its own.
    }
    window.setTimeout(() => setRefreshBusy(false), 2000);
  }, [refreshBusy, amsData?.selected_dev_id, machines, onRequestPushall]);

  // F4.7: follow Studio-wide machine switches while the dialog is open on
  // the AMS tab. If the user picks a different printer elsewhere in
  // Studio, mirror that selection here instead of staying on whichever
  // printer was active when the dialog opened.
  useEffect(() => {
    if (!open || mode !== 'ams' || amsLoading) return;
    if (!globalSelectedDev) return;
    const currentDev = amsData?.selected_dev_id || '';
    // Skip the mirror while we don't have a known snapshot yet. The
    // 1.5s poll can momentarily return an empty selected_dev_id when
    // DeviceManager::get_selected_machine is not ready; without this
    // guard the mirror would keep firing handleDeviceChange, which
    // toggles amsLoading and makes the whole AMS pane flicker.
    if (!currentDev) return;
    if (currentDev === globalSelectedDev) return;
    // Only follow if the new machine is actually in the dropdown list we
    // currently show; otherwise leave the user in their chosen state.
    if (!machines.some((m) => m.dev_id === globalSelectedDev)) return;
    // Mirror-only: the external switch has already called
    // set_selected_machine on the C++ side, so we just sync the UI and
    // re-read the AMS snapshot instead of triggering another set.
    void handleDeviceChange(globalSelectedDev, false);
    // Depend on the scalar `selected_dev_id` instead of the whole
    // amsData object — the 1.5s poll creates a new object reference on
    // every tick even when selected_dev_id doesn't actually change, and
    // re-running this effect on every tick is what caused the flicker.
  }, [open, mode, amsLoading, globalSelectedDev, amsData?.selected_dev_id, machines, handleDeviceChange]);

  // Live-refresh AMS data while the "Read from AMS" tab is open. Rationale:
  // once the user picks a printer, the C++ side keeps parsing fresh MQTT
  // push packets (MachineObject::parse_json) that mutate tray weight /
  // color / RFID / remain% in place. Without a live pull, the dialog keeps
  // showing the snapshot captured when the tab was opened, so a freshly
  // inserted / swapped spool never appears and `tray.weight` shown in the
  // form is stale. A lightweight 1.5 s poll is enough — the RPC payload is
  // a few KB and we keep the existing selection + form fields intact so
  // there is no visible flicker.
  // STUDIO-18344: poll tick reads / prunes the selected-slot Set so stale
  // keys (filament physically pulled out) drop off automatically.
  const selectedSlotKeysRef = useRef<Set<string>>(selectedSlotKeys);
  selectedSlotKeysRef.current = selectedSlotKeys;
  // Mirror amsData into a ref so the poll tick can diff the incoming
  // snapshot against the latest value without having to list amsData in
  // the effect's dep array (which would reset the interval timer).
  const amsDataRef = useRef<AmsData | null>(amsData);
  amsDataRef.current = amsData;
  // STUDIO-17989: also mirror selectedUnit / amsError so the poll tick
  // can self-heal the "first snapshot after machine switch was empty"
  // case without adding selectedUnit / amsError to the effect deps
  // (which would restart the 1.5s interval on every selection change
  // and flicker the dialog).
  const selectedUnitRef = useRef<string | null>(selectedUnit);
  selectedUnitRef.current = selectedUnit;
  const amsErrorRef = useRef<string>(amsError);
  amsErrorRef.current = amsError;
  useEffect(() => {
    if (!open || mode !== 'ams' || amsLoading) return;
    const devId = amsData?.selected_dev_id || '';
    if (!devId) return;

    let cancelled = false;
    const tick = async () => {
      try {
        // Read-only poll: omit both dev_id and switch_selected so C++
        // returns the AMS snapshot of the currently selected machine
        // without calling set_selected_machine. The previous version
        // passed dev_id here and produced a "set current printer" log
        // entry on every 1.5s tick.
        const data = await onFetchAmsData();
        if (cancelled || !data) return;

        // Coalesce identical snapshots. C++ re-builds ams_units from the
        // latest MachineObject state every poll, so we get a fresh object
        // reference on every tick even when nothing actually changed.
        // Pushing that through setAmsData would rerender the dialog and
        // restart every effect that depends on amsData, which is what
        // caused the visible flicker of the AMS pane. Only update state
        // when the serialized payload actually differs.
        const prev = amsDataRef.current;
        const same = prev && JSON.stringify(prev) === JSON.stringify(data);
        if (same) {
          // Even if snapshot hasn't changed, still handle the "Fetching AMS data…"
          // transient state so it doesn't get stuck.
          if (amsErrorRef.current === t('Fetching AMS data…')) {
            if (data.ams_units.length > 0) {
              // Device has AMS — clear the transient message immediately.
              emptyAmsPollCountRef.current = 0;
              setAmsError('');
            } else {
              // Still no AMS — advance counter and upgrade to real error after 2 ticks.
              emptyAmsPollCountRef.current += 1;
              if (emptyAmsPollCountRef.current >= 2) {
                setAmsError(t('No AMS detected on this device'));
              }
            }
          }
          return;
        }

        setAmsData(data);

        // STUDIO-17989: self-heal the "switched to an AMS-equipped printer
        // but the first snapshot landed with empty ams_units" case. In
        // switchToAms / handleDeviceChange we optimistically set
        //   amsError = "No AMS detected on this device"
        //   selectedUnit = null
        // whenever the initial fetch returns zero units, but the device
        // MQTT push often arrives one tick later. Once a subsequent poll
        // actually sees AMS units, drop the stale banner and auto-select
        // the first unit so the slot list renders without the user
        // having to click the AMS icon manually.
        if (data.ams_units.length > 0) {
          emptyAmsPollCountRef.current = 0;
          if (amsErrorRef.current) setAmsError('');
          if (selectedUnitRef.current == null) {
            setSelectedUnit(data.ams_units[0].ams_id);
          }
        } else if (amsErrorRef.current === t('Fetching AMS data…')) {
          emptyAmsPollCountRef.current += 1;
          if (emptyAmsPollCountRef.current >= 2) {
            setAmsError(t('No AMS detected on this device'));
          }
        }

        // STUDIO-18344: prune selected keys whose tray has disappeared
        // (filament physically pulled). The live tray is looked up on
        // demand from `amsData` so we no longer need to mirror tray
        // snapshots into local state; this loop only fires when the set
        // is non-empty so the no-selection case stays free.
        const cur = selectedSlotKeysRef.current;
        if (cur.size > 0) {
          const next = new Set<string>();
          for (const key of cur) {
            const [amsId, slotId] = key.split(':');
            const unit = data.ams_units.find((u) => u.ams_id === amsId);
            const tray = unit?.trays.find((tr) => tr.slot_id === slotId);
            if (tray && tray.is_exists) next.add(key);
          }
          if (next.size !== cur.size) {
            setSelectedSlotKeys(next);
            // Also clear the "form last seeded from this key" pointer if
            // the seeding slot is gone, so a subsequent fresh 1-select
            // will re-seed instead of being skipped as "already seeded".
            if (lastSeededSlotKeyRef.current && !next.has(lastSeededSlotKeyRef.current)) {
              lastSeededSlotKeyRef.current = '';
            }
          }
        }
      } catch {
        // Poll errors are non-fatal: the next tick will try again. We
        // deliberately do NOT surface `amsError` here because that would
        // nuke the user's current view on a transient hiccup.
      }
    };

    const timer = window.setInterval(tick, 1500);
    return () => {
      cancelled = true;
      window.clearInterval(timer);
    };
  }, [open, mode, amsLoading, amsData?.selected_dev_id, onFetchAmsData]);

  // Live-refresh the Printer dropdown while the AMS tab is open so
  // devices that come online / go offline / get (un)bound appear without
  // the user having to close and reopen the dialog. Runs at a lower rate
  // than the AMS tray poll because online state changes far less often
  // than tray RFID / weight / remain. Like the AMS tick this diffs
  // against the last payload and skips setState when nothing changed,
  // otherwise every tick would rerender the dialog for no reason.
  const machinesRef = useRef<MachineItem[]>(machines);
  machinesRef.current = machines;
  useEffect(() => {
    if (!open || mode !== 'ams' || amsLoading) return;
    let cancelled = false;
    const tick = async () => {
      try {
        const list = await onFetchMachines();
        if (cancelled || !Array.isArray(list)) return;
        const prev = machinesRef.current;
        if (JSON.stringify(prev) === JSON.stringify(list)) return;
        setMachines(list);
      } catch {
        // Poll errors are non-fatal; the next tick will retry.
      }
    };
    const timer = window.setInterval(tick, 3000);
    return () => {
      cancelled = true;
      window.clearInterval(timer);
    };
  }, [open, mode, amsLoading, onFetchMachines]);

  // STUDIO-18344: split out the form-seed body so the single-slot click,
  // the multi -> single deselect transition, and the polling slot-prune
  // path can all reuse the same setBrand / setMaterialType / setColor /
  // setWeights logic without going through the Set toggle helper.
  const seedFormFromTray = (unit: AmsUnit, tray: AmsTray) => {
    lastSeededSlotKeyRef.current = `${unit.ams_id}:${tray.slot_id}`;
    // Tell the fila_id reconcile effect: the next fila_id transition is
    // driven by us (we're about to setBrand/setMaterialType/setSeries based
    // on the tray's setting_id), not by a user-initiated brand switch.
    // The effect will align silently and skip snap-to-fallback so the
    // tray's real hex (which may be a custom colour absent from the new
    // palette) survives.  Cleared inside the effect after one use.
    amsSlotDrivenFilaIdSwapRef.current = true;
    // Historically we locked the form down when the tray reported an RFID
    // tag_uid (BBL original spool) so users could not accidentally change
    // authoritative fields. Product direction has since changed: the
    // Add-from-AMS flow must let the user correct every field before
    // saving (e.g. weigh the spool on a scale to override tray remain).
    // tag_uid is still captured in handleSubmit, only the read-only UI
    // gate has been removed.

    // F4.8: drive the whole form from the AMS tray. Previous implementation
    // only pushed sub_brands / fila_type / color / weight and left the form
    // defaults (spool=250g, initial=1000g) untouched, which meant the
    // weights shown in the form did not reflect the actual slot.
    //
    // Strategy (preferred order):
    //   1. Resolve (brand, material_type, series) via `setting_id`
    //      (reverse-lookup through presets). This is the most authoritative
    //      mapping because it comes straight from the Bambu preset used to
    //      print the spool.
    //   2. Fall back to sub_brands + fila_type string matching for trays
    //      that do not carry a setting_id (3rd-party / old firmware).

    let brandName  = '';
    let typeName   = '';
    let seriesName = '';
    let filamentName = '';

    const settingId = tray.setting_id || '';
    if (settingId) {
      // STUDIO-18110 / STUDIO-18117: AMS RFID 上的 setting_id 永远是云端官方
      // preset id。user-defined / cloud-pull 派生 preset 会和 system base
      // 共享 filament_id，find() 短路时可能命中错的那条，让 series 被填上
      // 未经规范化的 user alias，再由 cloud sync PUT body 兜底覆盖云端
      // spool 的 Material Type（=18117 重现链路）。反查必须跳过 is_user item。
      outer: for (const vendor of presets) {
        for (const tp of vendor.types) {
          const hit = tp.items?.find((it) =>
            !it.is_user && (it.setting_id === settingId || it.filament_id === settingId),
          );
          if (hit) {
            brandName  = vendor.name;
            typeName   = tp.name;
            seriesName = hit.series || '';
            filamentName = normalizePresetFilamentName(hit.name, vendor.name, tp.name, seriesName);
            break outer;
          }
        }
      }
    }

    if (!brandName) brandName = tray.sub_brands || '';
    if (!typeName) {
      const fullType = tray.fila_type || '';
      const typeCandidates = new Set<string>();
      const vendorsForMatch = brandName ? presets.filter((v) => v.name === brandName) : presets;
      vendorsForMatch.forEach((v) => v.types.forEach((tp) => { if (tp.name) typeCandidates.add(tp.name); }));
      let matchedType = '';
      let seriesRemainder = '';
      for (const cand of typeCandidates) {
        if (fullType === cand) { matchedType = cand; seriesRemainder = ''; break; }
        if (fullType.startsWith(cand + ' ') && cand.length > matchedType.length) {
          matchedType = cand;
          seriesRemainder = fullType.substring(cand.length + 1).trim();
        } else if (fullType.startsWith(cand) && cand.length > matchedType.length) {
          matchedType = cand;
          seriesRemainder = fullType.substring(cand.length).trim();
        }
      }
      typeName = matchedType;
      if (!seriesName) seriesName = seriesRemainder;
    }

    setBrand(brandName);
    setMaterialType(typeName);
    // Keep series aligned with the full cloud filamentName. When setting_id
    // resolves to a preset, trust that display name over AMS fila_type aliases
    // such as Sup.PLA.
    setSeries(filamentName || formatTypeSeries(typeName, seriesName));

    // F4.8: color may arrive as #RRGGBBAA (BBL firmware appends alpha for
    // transparent filaments) and historically *without* the leading `#`
    // for AMS multi-hex payloads (`0047BBFF`).  `normalizeColorCode` does
    // both: prefixes `#` if missing and slices to 7 chars (#RRGGBB) so
    // every downstream consumer (palette match, CSS gradient string,
    // preview-hex label) gets a canonical value.  Without this, an
    // un-prefixed hex flows into a CSS gradient and silently breaks.
    const sanitizedColor = normalizeColorCode(tray.color);
    if (sanitizedColor) setColorCode(sanitizedColor);

    // STUDIO-17977 F1.3: switching AMS slots must also reset the
    // gradient/multicolor pair (cols / ctype on the device side) and clear
    // the lingering FilamentColorCodeQuery name from the previous slot.
    // Without this, a slot-to-slot toggle keeps the old slot's `colors[]` /
    // `color_type` / `color_name` even though `color_code` has changed,
    // which is exactly what the F1.3 self-test caught: hex updates per slot
    // but the colour-name preview row keeps the previous slot's name.
    //
    // The actual canonical name is reapplied by the colorName-resolver
    // useEffect below as soon as the candidates for the new slot's
    // setting_id finish loading; we just need to make sure the form is in
    // a clean intermediate state so a stale label cannot leak through.
    // Same canonicalisation as `tray.color` above — AMS multi-hex payloads
    // routinely arrive as plain `RRGGBBAA` strings, which CSS gradients
    // refuse to parse.  Run every entry through `normalizeColorCode` so
    // both the AMS-card chip and the form's preview swatch get a list
    // CSS will actually paint.
    const traySanitizedColors = Array.isArray(tray.colors)
      ? tray.colors
          .map((c) => (typeof c === 'string' ? c : ''))
          .filter((c) => !!c)
          .map((c) => normalizeColorCode(c))
          .filter((c) => !!c)
      : [];
    // Form invariant established by AddEditDialog and consumed by
    // `isCandidateSelected`: `colors[]` is empty for single-hex spools and
    // populated only for gradient / multicolor.  Writing a one-element
    // array here would cause the resolver effect to miss every single-hex
    // candidate (the resolver bails out as soon as `colors.length > 0` on
    // a `color_type === 2` candidate), which is exactly how the AMS A1
    // single-hex slot ended up rendering its hex with an empty colour
    // name and missing BBL fila code.  Honour the invariant: only push
    // the hex list to `colors` when the slot is genuinely multi-hex.
    if (traySanitizedColors.length > 1) {
      setColors(traySanitizedColors);
      setColorType(tray.color_type === 1 ? 1 : 0);
    } else {
      setColors([]);
      setColorType(2);
    }
    setColorName(tray.color_name || '');
    setFilaColorCode(tray.fila_color_code || '');
    userTouchedColorRef.current = true;

    // Seed both weight inputs from the AMS tray report. `tray.weight` is
    // the spool's original 整卷净重 (MQTT `tray_weight`, always net); the
    // current net is `tray.weight * tray.remain%` via getTrayCurrentNetWeight.
    // No more 料盘 bookkeeping on this path — the cloud schema never stored
    // it anyway.
    const trayNetInit = parseInt(String(tray.weight ?? '0'), 10) || 0;
    const currentNet = getTrayCurrentNetWeight(tray);
    setTotalNetWeight(trayNetInit > 0 ? trayNetInit : 1000);
    setCurrentNetWeight(currentNet > 0 ? currentNet : (trayNetInit > 0 ? trayNetInit : 1000));
    setAmsLockedFields({
      brand: !!brandName,
      material: !!typeName || !!filamentName,
      color: !!sanitizedColor,
      weight: trayNetInit > 0 || currentNet > 0,
    });
  };

  // STUDIO-18344: resolve a slot key back to (unit, tray) using the live
  // amsData snapshot. Returns null when either side is missing so callers
  // can no-op rather than crash.
  const resolveSlotByKey = (key: string): { unit: AmsUnit; tray: AmsTray } | null => {
    if (!amsData || !key) return null;
    const [amsId, slotId] = key.split(':');
    const unit = amsData.ams_units.find((u) => u.ams_id === amsId);
    if (!unit) return null;
    const tray = unit.trays.find((t) => t.slot_id === slotId);
    if (!tray) return null;
    return { unit, tray };
  };

  // STUDIO-18344: per-slot toggle handler for the multi-select grid.
  //
  // Branches by the post-toggle Set size:
  //   - size 0  -> form keeps its previous values (UX continuity for
  //               "deselected by accident").
  //   - size 1  -> seed the form from the only selected tray, same as the
  //               pre-multi-select behaviour.
  //   - size N  -> form is hidden, no seeding required.
  const toggleSlotSelection = (unit: AmsUnit, tray: AmsTray) => {
    const key = `${unit.ams_id}:${tray.slot_id}`;
    const next = new Set(selectedSlotKeys);
    if (next.has(key)) {
      next.delete(key);
    } else {
      next.add(key);
    }
    setSelectedSlotKeys(next);
    if (next.size === 1) {
      const onlyKey = [...next][0];
      if (lastSeededSlotKeyRef.current !== onlyKey) {
        if (onlyKey === key) {
          seedFormFromTray(unit, tray);
        } else {
          const r = resolveSlotByKey(onlyKey);
          if (r) seedFormFromTray(r.unit, r.tray);
        }
      }
    } else if (next.size === 0) {
      // Allow a later 0 -> 1 transition to reseed even if the form still
      // shows the last-selected tray's values.
      lastSeededSlotKeyRef.current = '';
    }
  };

  // STUDIO-18344: convenience "select every detected slot in the current
  // unit" action. Trays without RFID are still importable (they fall back
  // to the manual create path on the C++ side), so the only filter is
  // `is_exists`. Selection is keyed per (ams_id, slot_id) so this never
  // collides with other AMS units' slots already in the Set.
  const selectAllDetected = (unit: AmsUnit) => {
    const next = new Set(selectedSlotKeys);
    for (const tray of unit.trays) {
      if (tray.is_exists) next.add(`${unit.ams_id}:${tray.slot_id}`);
    }
    setSelectedSlotKeys(next);
    // Reseed the form if the resulting set collapses back to a single
    // entry (e.g. the unit only had one populated slot). Most of the
    // time this will land at size >= 2 and the form stays hidden.
    if (next.size === 1) {
      const onlyKey = [...next][0];
      if (lastSeededSlotKeyRef.current !== onlyKey) {
        const r = resolveSlotByKey(onlyKey);
        if (r) seedFormFromTray(r.unit, r.tray);
      }
    }
  };

  const clearSlotSelection = () => {
    setSelectedSlotKeys(new Set());
    lastSeededSlotKeyRef.current = '';
  };

  // F4.10: dialog drag support. Users expect to be able to drag the dialog
  // around by its header so it doesn't cover underlying context.
  const [dragOffset, setDragOffset] = useState<{ x: number; y: number }>({ x: 0, y: 0 });
  const dragState = useRef<{ startX: number; startY: number; baseX: number; baseY: number } | null>(null);

  // Reset drag offset whenever dialog is re-opened.
  useEffect(() => { if (open) setDragOffset({ x: 0, y: 0 }); }, [open]);

  const handleDragMove = useCallback((e: MouseEvent) => {
    const st = dragState.current;
    if (!st) return;
    setDragOffset({ x: st.baseX + (e.clientX - st.startX), y: st.baseY + (e.clientY - st.startY) });
  }, []);
  const handleDragEnd = useCallback(() => {
    dragState.current = null;
    window.removeEventListener('mousemove', handleDragMove);
    window.removeEventListener('mouseup', handleDragEnd);
    document.body.style.userSelect = '';
  }, [handleDragMove]);
  const handleDragStart = useCallback((e: React.MouseEvent) => {
    // Ignore drags that start on interactive controls (e.g. close button).
    const target = e.target as HTMLElement;
    if (target.closest('button, input, select, textarea, a')) return;
    dragState.current = { startX: e.clientX, startY: e.clientY, baseX: dragOffset.x, baseY: dragOffset.y };
    window.addEventListener('mousemove', handleDragMove);
    window.addEventListener('mouseup', handleDragEnd);
    document.body.style.userSelect = 'none';
    e.preventDefault();
  }, [dragOffset, handleDragMove, handleDragEnd]);
  const resetDragOffset = useCallback(() => setDragOffset({ x: 0, y: 0 }), []);

  if (!open) return null;

  const currentUnit = amsData?.ams_units.find((u) => u.ams_id === selectedUnit);
  const slotLabels = ['A1', 'A2', 'A3', 'A4'];
  // STUDIO-18344: form lock + form visibility derive from the new selection
  // model. Multi-select (>=2) hides the form entirely, so the lock flags
  // only matter in single-select mode.
  const slotSelectionCount = selectedSlotKeys.size;
  const isAmsMultiSelect = mode === 'ams' && slotSelectionCount >= 2;
  const isAmsSingleSelect = mode === 'ams' && slotSelectionCount === 1;
  const amsFieldLocked = isAmsSingleSelect;
  // When editing an existing RFID spool, lock everything except the note field.
  const isRfidEdit = isEdit && hasCloudRfid(initSpool?.tag_uid ?? '');
  const lockBrand = (amsFieldLocked && amsLockedFields.brand) || isRfidEdit;
  const lockMaterial = (amsFieldLocked && amsLockedFields.material) || isRfidEdit;
  const lockColor = (amsFieldLocked && amsLockedFields.color) || isRfidEdit;
  const lockWeight = amsFieldLocked && amsLockedFields.weight;
  // Snapshot of (unit, tray) pairs for the batch summary panel. Resolved
  // against the live `amsData` so a slot whose tray was just pulled drops
  // out automatically on the next render (the poll-prune effect will catch
  // up to the Set itself on the next 1.5s tick).
  const batchSelectionItems = isAmsMultiSelect
    ? Array.from(selectedSlotKeys)
        .map((key) => {
          const r = resolveSlotByKey(key);
          if (!r) return null;
          return { key, unit: r.unit, tray: r.tray };
        })
        .filter((x): x is { key: string; unit: AmsUnit; tray: AmsTray } => x !== null)
    : [];
  const batchUpdateCount = batchSelectionItems.reduce((count, item) => {
    const rawTrayTagUid = item.tray.tag_uid || '';
    const trayTagUid = hasCloudRfid(rawTrayTagUid) ? rawTrayTagUid : '';
    if (!hasCloudRfid(trayTagUid)) return count;
    return spools.some((sp) => (sp.tag_uid || '') === trayTagUid) ? count + 1 : count;
  }, 0);

  return (
    <>
    <div className="fixed inset-0 bg-black/50 flex items-start justify-center pt-10 z-[1000]">
      <div
        data-testid={isEdit ? 'edit-dialog' : 'add-dialog'}
        data-mode={mode}
        className="w-[644px] max-h-[calc(100vh-80px)] bg-[#242424] [html[data-theme=light]_&]:bg-fm-sidebar rounded-lg shadow-[0px_8px_24px_0px_rgba(0,0,0,0.12)] flex flex-col overflow-hidden fm-native-form"
        style={{ transform: `translate(${dragOffset.x}px, ${dragOffset.y}px)` }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header — drag handle (F4.10). Double-click resets position. */}
        <div
          className="flex items-center justify-between h-[40px] pl-[24px] pr-[8px] shrink-0 relative cursor-move select-none"
          onMouseDown={handleDragStart}
          onDoubleClick={resetDragOffset}
          title={t('Drag to move')}
        >
          <h3 className="text-[14px] font-bold leading-[22px] text-fm-text-strong truncate">{isEdit ? t('Edit Filament') : t('Add Filament')}</h3>
          <button className="size-[24px] rounded-[6px] flex items-center justify-center bg-transparent border-none text-fm-text-detail cursor-pointer hover:text-fm-text-strong hover:bg-fm-hover" onClick={onClose}>
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M4 4l8 8M12 4l-8 8" stroke="currentColor" strokeWidth="1.2"/></svg>
          </button>
          <div className="absolute bottom-0 left-0 right-0 h-px bg-fm-border" />
        </div>

        {/* Scrollable content */}
        <div className="flex-1 overflow-y-auto">
        <div className="flex flex-col gap-[24px] p-[24px]">

        {/* Mode tabs — only in add mode */}
        {!isEdit && (
          <div className="flex gap-[16px] items-start w-full">
            <div
              data-testid="dialog-tab-manual"
              data-active={mode === 'manual' ? 'true' : 'false'}
              className={`flex-1 flex items-center justify-center py-[4px] px-[16px] cursor-pointer rounded-[8px] border transition-all duration-150 ${mode === 'manual' ? 'border-fm-brand text-[#50e81d]' : 'border-fm-border-focus text-fm-text-primary hover:bg-fm-hover'}`}
              onClick={() => setMode('manual')}
            ><span className="py-[5px] text-[14px] leading-[22px]">{t('Manual Add')}</span></div>
            <div
              data-testid="dialog-tab-ams"
              data-active={mode === 'ams' ? 'true' : 'false'}
              className={`flex-1 flex items-center justify-center py-[4px] px-[8px] cursor-pointer rounded-[8px] border transition-all duration-150 ${mode === 'ams' ? 'border-fm-brand text-[#50e81d]' : 'border-fm-border-focus text-fm-text-primary hover:bg-fm-hover'}`}
              onClick={switchToAms}
            ><span className="py-[5px] text-[14px] leading-[22px]">{t('Read from AMS')}</span></div>
          </div>
        )}

        {/* AMS Section — always show a printer picker row (F4.7); errors are inline, not a blank page */}
        {mode === 'ams' && (
          <div className="flex flex-col gap-[16px]">
            <div className="flex items-center gap-[6px]">
              <div className="w-[2px] h-[16px] rounded-[10px] bg-[#50e81d]" />
              <span className="text-[14px] leading-[22px] text-fm-text-primary">{t('Select Device')}</span>
            </div>

            {amsLoading && (
              <div className="text-center text-fm-text-detail text-xs py-4">{t('Fetching device info...')}</div>
            )}

            {!amsLoading && (
              <div className="flex flex-col gap-[10px] rounded-[8px] border border-fm-border-focus bg-fm-inner p-3">
                <label className="text-[11px] leading-[16px] text-fm-text-secondary">{t('Printer')}</label>
                <div className="flex items-center gap-[8px]">
                  <select
                    className="flex-1 min-h-[36px] rounded-[6px] bg-fm-inner2 px-[8px] text-fm-text-strong text-xs outline-none focus:shadow-[0_0_0_1px_var(--color-fm-brand)] fm-select-arrow cursor-pointer disabled:cursor-not-allowed disabled:opacity-60"
                    value={machines.length ? (amsData?.selected_dev_id || machines[0]?.dev_id || '') : ''}
                    disabled={machines.length === 0}
                    onChange={(e) => { if (e.target.value) void handleDeviceChange(e.target.value); }}
                  >
                    {machines.length === 0 ? (
                      <option value="">{t('No printers — sign in and bind a device')}</option>
                    ) : (
                      machines.map((m) => (
                        // Label follows SelectMachineDialog's "<dev_name>(LAN)"
                        // convention; online/offline state is conveyed by the
                        // AMS snapshot state in the pane below, not by the
                        // dropdown text.
                        <option key={m.dev_id} value={m.dev_id}>
                          {m.dev_name || m.dev_id}{m.is_lan ? '(LAN)' : ''}
                        </option>
                      ))
                    )}
                  </select>
                  <button
                    type="button"
                    className="shrink-0 w-[32px] h-[32px] rounded-[6px] border border-fm-border-focus bg-fm-inner2 text-fm-text-secondary flex items-center justify-center hover:text-fm-text-strong hover:border-fm-text-secondary disabled:cursor-not-allowed disabled:opacity-50 transition-colors"
                    title={t('Refresh printer status')}
                    aria-label={t('Refresh printer status')}
                    disabled={machines.length === 0 || refreshBusy}
                    onClick={() => { void handleRequestPushall(); }}
                  >
                    <svg width="14" height="14" viewBox="0 0 14 14" fill="none" className={refreshBusy ? 'animate-spin' : ''}>
                      <path d="M11.5 3.5A5 5 0 1 0 12 8" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" fill="none"/>
                      <path d="M12 2v3h-3" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
                    </svg>
                  </button>
                </div>
                {machines.length === 0 && (
                  <p className="text-[11px] leading-[16px] text-fm-text-detail m-0">{t('No printer found, please ensure logged in and device bound')}</p>
                )}
              </div>
            )}

            {!!amsError && !amsLoading && (
              <div className="text-xs text-fm-warning leading-[19px] px-1">{amsError}</div>
            )}

            {!amsLoading && machines.length > 0 && (
              <div data-testid="ams-grid" className="flex flex-col gap-[4px]">
                <div className="flex items-center gap-[12px]">
                  <div className="flex flex-1 gap-[12px] items-center justify-end min-w-0">
                    {amsData?.ams_units.map((u) => (
                      <button
                        key={u.ams_id}
                        type="button"
                        data-testid={`ams-unit-${u.ams_id}`}
                        data-active={u.ams_id === selectedUnit ? 'true' : 'false'}
                        className={`rounded-[4px] border bg-transparent cursor-pointer flex items-center p-[4px] transition-colors duration-150 hover:border-fm-text-secondary ${u.ams_id === selectedUnit ? 'border-fm-brand' : 'border-fm-border-focus'}`}
                        title={`AMS ${parseInt(u.ams_id, 10) + 1}`}
                        // STUDIO-18344: switching AMS unit keeps the
                        // selected slots across units (per the ticket UX
                        // confirmation). Only handleDeviceChange clears.
                        onClick={() => setSelectedUnit(u.ams_id)}
                      >
                        <AmsUnitIcon unit={u} isActive={u.ams_id === selectedUnit} />
                      </button>
                    ))}
                  </div>
                </div>
                {currentUnit && (
                  <>
                  {/* STUDIO-18344: multi-select toolbar. Always rendered
                      so the testids/test hooks exist regardless of count;
                      counts and helper actions surface the current
                      selection state for the user. */}
                  <div className="flex items-center justify-between px-[2px]">
                    <span
                      data-testid="ams-selection-count"
                      data-count={slotSelectionCount}
                      className="text-[11px] leading-[16px] text-fm-text-detail"
                    >
                      {slotSelectionCount > 0
                        ? t('Selected {{count}} slots', { count: slotSelectionCount })
                        : t('Tap slots to select; pick multiple to batch-add')}
                    </span>
                    <div className="flex items-center gap-[12px]">
                      <button
                        type="button"
                        data-testid="ams-select-all"
                        className="bg-transparent border-none p-0 text-[11px] leading-[16px] text-fm-text-secondary hover:text-fm-text-strong cursor-pointer disabled:opacity-40 disabled:cursor-default"
                        disabled={!currentUnit.trays.some((tr) => tr.is_exists)}
                        onClick={() => selectAllDetected(currentUnit)}
                      >
                        {t('Select all detected')}
                      </button>
                      <button
                        type="button"
                        data-testid="ams-clear-selection"
                        className="bg-transparent border-none p-0 text-[11px] leading-[16px] text-fm-text-secondary hover:text-fm-text-strong cursor-pointer disabled:opacity-40 disabled:cursor-default"
                        disabled={slotSelectionCount === 0}
                        onClick={clearSlotSelection}
                      >
                        {t('Clear Selection')}
                      </button>
                    </div>
                  </div>
                  <div className="flex gap-[8px] py-[8px]">
                    {currentUnit.trays.map((tray, i) => {
                      const label = slotLabels[i] || `A${i + 1}`;
                      const slotKey = `${currentUnit.ams_id}:${tray.slot_id}`;
                      const isSelected = selectedSlotKeys.has(slotKey);
                      if (!tray.is_exists) {
                        return (
                          <div key={label} data-testid={`ams-slot-${currentUnit.ams_id}-${tray.slot_id}`} data-empty="true" className="flex-1 flex flex-col rounded-[6px] border border-fm-border-focus cursor-default opacity-30 transition-all duration-150 overflow-hidden">
                            <div className="fm-slot-header-bg text-center py-[2px] text-[11px] leading-[16px] bg-[var(--color-fm-slot-header)] text-[var(--color-fm-slot-header-text)] rounded-t-[6px]">{label}</div>
                            <div className="flex gap-[4px] items-center p-[4px]">
                            <div className="size-[40px] shrink-0 flex items-center justify-center">
                                <SpoolColorChip colorCode="#555" size={32} />
                              </div>
                              <div className="flex-1 flex flex-col gap-[4px] min-w-0">
                                <span className="text-[12px] leading-[19px] text-fm-text-primary truncate">{t('Empty')}</span>
                              </div>
                            </div>
                          </div>
                        );
                      }
                      return (
                        <div
                          key={label}
                          data-testid={`ams-slot-${currentUnit.ams_id}-${tray.slot_id}`}
                          data-empty="false"
                          data-selected={isSelected ? 'true' : 'false'}
                          data-color={tray.color}
                          data-color-type={tray.color_type}
                          data-colors={(tray.colors || []).join(',')}
                          className={`relative flex-1 flex flex-col rounded-[6px] border cursor-pointer transition-all duration-150 overflow-hidden hover:border-fm-text-secondary ${isSelected ? 'border-fm-brand' : 'border-fm-border-focus'}`}
                          onClick={() => toggleSlotSelection(currentUnit, tray)}
                        >
                          {/* STUDIO-18344: corner checkbox surfaces the
                              multi-select affordance. Always rendered
                              (also on size 1) so users discover the
                              capability without needing to click a
                              second slot first. */}
                          <span
                            data-testid="ams-slot-checkbox"
                            data-checked={isSelected ? 'true' : 'false'}
                            aria-hidden="true"
                            className={`absolute top-[4px] right-[4px] size-[14px] rounded-[3px] flex items-center justify-center pointer-events-none transition-colors duration-150 ${isSelected ? 'bg-fm-brand text-white' : 'bg-fm-inner2 border border-fm-border-focus text-transparent'}`}
                          >
                            <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M2 5.2 4.2 7.4 8.5 2.8" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
                          </span>
                          <div className={`fm-slot-header-bg text-center py-[2px] text-[11px] leading-[16px] bg-[var(--color-fm-slot-header)] text-[var(--color-fm-slot-header-text)] rounded-t-[6px] ${isSelected ? '!bg-fm-brand !text-white' : ''}`}>{label}</div>
                          <div className="flex gap-[4px] items-center p-[4px]">
                            <div className="size-[40px] shrink-0 flex items-center justify-center">
                              <SpoolColorChip colorCode={tray.color} colors={tray.colors} colorType={tray.color_type} size={32} />
                            </div>
                            <div className="flex-1 flex flex-col gap-[4px] min-w-0">
                              <div className="text-[12px] leading-[19px] text-fm-text-primary flex items-center gap-[4px] truncate">
                                <SpoolColorChip
                                  colorCode={tray.color}
                                  colors={tray.colors}
                                  colorType={tray.color_type}
                                  size={14}
                                  radius={3}
                                />
                                {tray.fila_type || '—'}
                              </div>
                              {/* Show the *remaining* net weight in each
                                  slot card (initial_net * remain%) so the
                                  user sees the live AMS reading, not the
                                  spool's brand-new / factory value. */}
                              <div className="text-[12px] leading-[19px] text-fm-text-secondary">
                                {(() => {
                                  const cur = getTrayCurrentNetWeight(tray);
                                  return cur > 0 ? `${cur}g` : '—';
                                })()}
                              </div>
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                  </>
                )}
                {/* STUDIO-18344: batch summary panel — only shown when the
                    user has ticked >=2 slots. The editable form below is
                    hidden in this state so users see exactly what will
                    land in the cloud after pressing the confirm button. */}
                {isAmsMultiSelect && (
                  <div
                    data-testid="ams-batch-summary"
                    data-count={slotSelectionCount}
                    data-update-count={batchUpdateCount}
                    className="flex flex-col gap-[8px] rounded-[8px] border border-fm-border-focus bg-fm-inner p-3"
                  >
                    <div className="text-[12px] leading-[19px] text-fm-text-primary">
                      {t('{{count}} slots will be batch-added using AMS data', { count: slotSelectionCount })}
                    </div>
                    {batchUpdateCount > 0 && (
                      <div className="text-[11px] leading-[16px] text-fm-text-detail">
                        {t('Some slots already exist; they will be updated')}
                      </div>
                    )}
                    <div className="flex flex-wrap gap-[6px]">
                      {batchSelectionItems.map((item) => (
                        <div
                          key={item.key}
                          data-testid={`ams-batch-item-${item.unit.ams_id}-${item.tray.slot_id}`}
                          className="flex items-center gap-[6px] rounded-[6px] bg-fm-inner2 pl-[6px] pr-[8px] py-[4px]"
                          title={`${item.tray.fila_type || ''} ${item.tray.color || ''}`.trim()}
                        >
                          <SpoolColorChip
                            colorCode={item.tray.color}
                            colors={item.tray.colors}
                            colorType={item.tray.color_type}
                            size={14}
                            radius={3}
                          />
                          <span className="text-[11px] leading-[16px] text-fm-text-primary truncate max-w-[120px]">
                            {item.tray.fila_type || '—'}
                          </span>
                          <span className="text-[11px] leading-[16px] text-fm-text-detail">
                            {(() => {
                              const cur = getTrayCurrentNetWeight(item.tray);
                              return cur > 0 ? `${cur}g` : '—';
                            })()}
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {/* Separator between AMS and form */}
        {isAmsSingleSelect && <div className="h-0 w-full border-t border-fm-border" />}

        {/* Form body — visible in manual mode, or in AMS when exactly one
            slot is selected. Multi-select (>=2) hides the form entirely
            (STUDIO-18344). */}
        {(mode === 'manual' || isAmsSingleSelect) && (
          <div className="flex flex-col gap-[12px]">
            {/* Section title: 耗材信息 */}
            <div className="flex flex-col gap-[16px]">
              <div className="flex items-center gap-[6px]">
                <div className="w-[2px] h-[16px] rounded-[10px] bg-[#50e81d]" />
                <span className="text-[14px] leading-[22px] text-fm-text-strong">{t('Filament Info')}</span>
              </div>

              {/* Brand / Material Type — 2 columns.
                  Series has been merged into Material Type per F4.3 feedback;
                  options look like "PLA Basic" / "PLA Matte" and we split the
                  combined string back into material_type + series internally. */}
              <div className="flex gap-[12px]">
                <div className="flex flex-col gap-[4px] flex-1 pb-[24px]">
                  <label className="text-[12px] leading-[19px] text-fm-text-secondary"><span className="text-[#ff2b00]">*</span> {t('Brand')}</label>
                  <select
                    data-testid="filament-brand"
                    className="bg-fm-inner2 border-none rounded-[6px] h-[32px] pl-[8px] pr-[4px] text-fm-text-strong text-[12px] leading-[19px] outline-none w-full focus:shadow-[0_0_0_1px_var(--color-fm-brand)] fm-select-arrow cursor-pointer disabled:cursor-not-allowed disabled:opacity-60"
                    value={brand}
                    disabled={lockBrand}
                    onChange={(e) => {
                      setBrand(e.target.value);
                      if (!lockMaterial) {
                        setMaterialType('');
                        setSeries('');
                      }
                    }}
                  >
                    <option value="">{t('Select Brand')}</option>
                    {mergedVendorNames.map((n) => <option key={n} value={n}>{n}</option>)}
                  </select>
                </div>
                <div className="flex flex-col gap-[4px] flex-1 pb-[24px]">
                  <label className="text-[12px] leading-[19px] text-fm-text-secondary"><span className="text-[#ff2b00]">*</span> {t('Material Type')}</label>
                  {/* F4.3: Must pick a brand first.  When brand is empty the
                      options list would be the union of all vendors' types
                      and that confuses users into thinking they can pick
                      before a brand is set — disable the control instead and
                      show a hint placeholder. */}
                  <select
                    data-testid="filament-material"
                    className="bg-fm-inner2 border-none rounded-[6px] h-[32px] pl-[8px] pr-[4px] text-fm-text-strong text-[12px] leading-[19px] outline-none w-full focus:shadow-[0_0_0_1px_var(--color-fm-brand)] fm-select-arrow cursor-pointer disabled:cursor-not-allowed disabled:opacity-60"
                    value={typeSeriesFull}
                    onChange={(e) => handleTypeSeriesChange(e.target.value)}
                    disabled={!brand || lockMaterial}
                  >
                    <option value="">{!brand ? t('Select Brand First') : t('Select Type')}</option>
                    {/* Edit 场景兜底：本地 spool 的 material_type/series 组合可能来源于
                        AMS 同步、自定义添加、或更早版本的 presets 数据，不一定出现在当前
                        brand 的 typeSeriesOptions 里。没有这个 fallback option 时 <select>
                        找不到匹配项会回落到 placeholder "Select Type"，造成编辑时看上去
                        "耗材类型未展示"。把当前值单独补一条，保证可回显、可修改。*/}
                    {typeSeriesFull && !typeSeriesOptions.includes(typeSeriesFull) && (
                      <option value={typeSeriesFull}>{typeSeriesFull}</option>
                    )}
                    {typeSeriesOptions.map((n) => <option key={n} value={n}>{n}</option>)}
                  </select>
                </div>
              </div>

              {/* Color palette. F4.4 feedback: 自定义颜色需要"可保存 / 能看到已选"。
                  "+" 始终保留为取色入口；新取的自定义色追加到预设色之后。 */}
              <div className="flex flex-col gap-[8px]">
                <label className="text-[12px] leading-[19px] text-fm-text-secondary"><span className="text-[#ff2b00]">*</span> {t('Color')}</label>
                <div data-testid="color-candidate-panel" className={`flex flex-wrap gap-[6px] items-center ${lockColor ? 'pointer-events-none opacity-60' : ''}`}>
                  {/* STUDIO-18114: Custom-color picker — click "+" to open a
                      draft popover; the form's color is only updated after
                      the user explicitly confirms with OK. */}
                  <div ref={colorPickerRef} className="relative">
                    <button
                      type="button"
                      data-testid="pick-custom-color-button"
                      className="size-[24px] rounded-[4px] cursor-pointer border border-dashed border-fm-border-focus bg-fm-inner overflow-hidden flex items-center justify-center text-fm-text-detail text-sm hover:border-fm-text-secondary disabled:cursor-not-allowed disabled:opacity-60 p-0"
                      title={t('Pick Custom Color')}
                      aria-label={t('Pick Custom Color')}
                      aria-haspopup="dialog"
                      aria-expanded={colorPickerOpen}
                      disabled={lockColor}
                      onClick={openColorPicker}
                    >
                      <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M7 2v10M2 7h10" stroke="currentColor" strokeWidth="1.2"/></svg>
                    </button>
                    {colorPickerOpen && (
                      <div
                        role="dialog"
                        aria-label={t('Pick Custom Color')}
                        className="absolute left-0 top-[calc(100%+8px)] z-[1100] w-[224px] flex flex-col gap-[12px] rounded-[10px] border border-fm-border bg-fm-base p-[14px] shadow-[0_12px_32px_rgba(0,0,0,0.5)]"
                      >
                        {/* STUDIO-18137: on macOS WKWebView the system
                            color picker is anchored to the <input
                            type="color"> element's bounding rect. When
                            the input is hidden via Tailwind's `sr-only`
                            (clip:rect(0,0,0,0), width/height:1px) WebKit
                            cannot compute a valid anchor and falls back
                            to the bottom-left corner of the screen.
                            Wrap the input in a <label> sized like the
                            swatch and make the input a transparent
                            overlay so WebKit always sees a real anchor.
                            STUDIO-18114's draft-then-commit flow is
                            preserved: input.onChange still only writes
                            draftColor; OK/Cancel still gate the commit. */}
                        <div className="flex items-center gap-[12px]">
                          <label
                            className="relative size-[56px] shrink-0 rounded-[8px] border border-fm-border-focus cursor-pointer block overflow-hidden focus-within:ring-2 focus-within:ring-fm-brand transition-shadow"
                            style={{ background: draftColor }}
                            title={t('Pick Custom Color')}
                          >
                            <input
                              ref={nativeColorInputRef}
                              type="color"
                              value={draftColor || '#000000'}
                              onChange={(e) => setDraftColor(e.target.value)}
                              autoFocus
                              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                              aria-label={t('Pick Custom Color')}
                            />
                          </label>
                          <div className="flex flex-col gap-[4px] min-w-0 flex-1">
                            <span className="text-[10px] leading-[12px] text-fm-text-detail uppercase tracking-wider">
                              {t('Custom Color')}
                            </span>
                            <span className="text-[13px] leading-[18px] text-fm-text-strong font-mono tracking-wider">
                              {(draftColor || '#000000').toUpperCase()}
                            </span>
                          </div>
                        </div>
                        <div className="flex justify-end gap-[8px]">
                          <button
                            type="button"
                            className="h-[28px] px-[14px] rounded-[6px] cursor-pointer text-[12px] leading-[19px] bg-fm-input text-fm-text-primary border-none hover:bg-fm-hover"
                            onClick={cancelCustomColor}
                          >{t('Cancel')}</button>
                          <button
                            type="button"
                            className="h-[28px] px-[14px] rounded-[6px] border-none cursor-pointer text-[12px] leading-[19px] font-medium bg-fm-brand text-white hover:bg-fm-brand-hover"
                            onClick={confirmCustomColor}
                          >{t('OK')}</button>
                        </div>
                      </div>
                    )}
                  </div>
                  {/* STUDIO-17977 / Task 10: query-driven palette. The list
                      of swatches comes from `filament.colors.query_for_id`
                      (cached by fila_id in zustand) instead of a hardcoded
                      hex array, so gradient and multicolor presets are
                      first-class swatches.
                      Follow-up requirement 3: when the strict per-fila_id
                      query returns nothing (non-official spool, or filaId
                      not yet picked), `effectiveCandidates` falls back to
                      "all official colours of the same material_type"
                      aggregated client-side from the prefetched cache.
                      Picking a fallback swatch only seeds the colour
                      triple - the spool's setting_id is not rewritten
                      (Q3 = keep_setting_id, "borrow colour, not identity").
                      Empty state covers the case where neither path yields
                      anything (e.g. material_type also unset). */}
                  {effectiveCandidates.length === 0 && customColors.length === 0 && (
                    <div className="text-[11px] leading-[16px] text-fm-text-detail">
                      {t('No predefined colors for this filament')}
                    </div>
                  )}
                  {effectiveCandidates.map((c) => {
                    const selected = isCandidateSelected(c);
                    // STUDIO-17977: 24×24 button wraps a SpoolColorChip so
                    // single / multicolor / gradient candidates render via
                    // the same component used by every other surface
                    // (list / detail / AMS / preview). The button itself
                    // owns the selection ring, so the inner chip is drawn
                    // with `border={false}` to avoid a double outline.
                    const cHexes = (c.colors || [])
                      .map((h) => normalizeColorCode(h))
                      .filter((h) => h.length > 0);
                    return (
                      <button
                        key={`${c.color_code}|${(c.colors || []).join(',')}`}
                        type="button"
                        data-testid={`color-candidate-${c.color_code}`}
                        data-color-code={c.color_code}
                        data-color-name={c.name}
                        data-color-type={c.color_type}
                        data-colors={(c.colors || []).join(',')}
                        data-selected={selected ? 'true' : 'false'}
                        title={c.name}
                        aria-label={c.name}
                        onClick={() => onPickCandidate(c)}
                        className={`size-[24px] rounded-[4px] p-0 cursor-pointer transition-colors duration-150 border hover:border-fm-text-secondary bg-transparent inline-flex items-center justify-center ${selected ? 'border-fm-brand border-2' : 'border-fm-border-focus'}`}
                      >
                        <SpoolColorChip
                          colorCode={cHexes[0] || ''}
                          colors={c.colors}
                          colorType={c.color_type as 0 | 1 | 2 | undefined}
                          size={22}
                          radius={3}
                          border={false}
                        />
                      </button>
                    );
                  })}
                  {customColors.map((c) => {
                    // A custom swatch is "selected" only when the form is
                    // in single-colour mode AND the hex matches; otherwise
                    // the user has since picked a multicolor candidate and
                    // the visual highlight should follow that.
                    const isSelected = colors.length === 0
                      && c.toUpperCase() === colorCode.toUpperCase();
                    return (
                      <div
                        key={`custom-${c}`}
                        className={`size-[24px] rounded-[4px] cursor-pointer border transition-colors duration-150 hover:border-fm-text-secondary inline-flex items-center justify-center bg-transparent ${isSelected ? 'border-fm-brand border-2' : 'border-fm-border-focus'}`}
                        title={t('Custom Color')}
                        onClick={() => onPickCustomSwatch(c)}
                      >
                        <SpoolColorChip colorCode={c} size={22} radius={3} border={false} />
                      </div>
                    );
                  })}
                </div>
                {/* Selected-color preview bar — always visible once a color is picked. */}
                {/*
                  STUDIO-17977 F1.3: previously this row only showed the
                  primary hex and a literal "Custom Color" / "Preset Color"
                  badge driven by a stale BAMBU_COLORS membership check.
                  The new layout, in left-to-right order:
                    [swatch] [colour name?] [BBL official code?] [hex list]
                  - Swatch reuses the same flat CSS gradient strip as the
                    24×24 candidate panel so single / gradient / multicolor
                    selections look identical between the two.
                  - Colour name is the FilamentColorCodeQuery candidate
                    name, surfaced only when a match exists.
                  - BBL official code (e.g. "Q01B00" / "13903") is the
                    candidate.color_code returned by the same RPC; the
                    in-form `colorCode` state is the *primary hex*, so do
                    not confuse the two - they share a name only by
                    historical accident.
                  - Hex list expands `colors[]` for gradient / multicolor
                    selections so the row carries every constituent hex,
                    not just the primary. Single-colour rows still show
                    one hex.
                */}
                {colorCode && (
                  <div data-testid="color-preview-bar" className="flex items-center gap-[8px] bg-fm-inner rounded-[6px] px-[8px] py-[6px] flex-wrap">
                    <span
                      data-testid="preview-swatch"
                      data-swatch-bg={previewSwatchBackground}
                      className="inline-flex shrink-0"
                    >
                      <SpoolColorChip
                        colorCode={colorCode}
                        colors={colors}
                        colorType={colorType as 0 | 1 | 2 | undefined}
                        size={16}
                        radius={3}
                      />
                    </span>
                    {colorName && (
                      <span data-testid="preview-color-name" className="text-[11px] leading-[16px] text-fm-text-secondary shrink-0">
                        {colorName}
                      </span>
                    )}
                    {filaColorCode && (
                      <span
                        data-testid="preview-fila-code"
                        className="text-[11px] leading-[16px] text-fm-text-detail shrink-0"
                        title={t('Bambu Color Code')}
                      >
                        · {filaColorCode}
                      </span>
                    )}
                    <span data-testid="preview-hex-list" className="text-[11px] leading-[16px] text-fm-text-primary font-mono tracking-wider break-all">
                      {previewHexLabel}
                    </span>
                  </div>
                )}
              </div>

              {/* Weight — swagger-aligned two-field model
                  (design-user.api: netWeight + totalNetWeight). The old
                  三列 "Total - Spool = Net" UX was dropped because the
                  cloud never round-trips spool_weight, so it only ever
                  confused the Remain column. */}
              <div className="flex flex-col gap-[4px]">
                <label className="text-[12px] leading-[19px] text-fm-text-secondary"><span className="text-[#ff2b00]">*</span> {t('Weight')}</label>
                <div className="bg-fm-inner rounded-[6px] p-[8px]">
                  <div className="flex gap-[8px] items-center">
                    <div className="flex flex-col gap-[4px] flex-1">
                      <span className="text-[11px] leading-[16px] text-fm-text-secondary">{t('Current Net Weight')}</span>
                      {/* type=number inputs bound to a number state in
                          React keep showing "0" after the user deletes
                          the last digit (Number("") -> 0), so the next
                          keystroke appends "1" and you get "01". Select
                          all text on focus so typing always replaces the
                          previous value, matching the usual UX for
                          quantity-style fields. Pipe through
                          sanitizeWeightInput first to strip leading-zero
                          residue from a backspace-clear flow (STUDIO-17958),
                          then clampWeight to enforce [0, MAX_NET_WEIGHT_GRAMS]
                          (STUDIO-17959) so a paste of an int32-overflow
                          value can't slip through to handleSubmit; the
                          native min/max attributes also stop the browser
                          spinner from going past the cap.
                          The trailing "g" span is the unit indicator —
                          pure decoration so users don't have to guess
                          whether the field expects grams or kilograms. */}
                      <div className="flex items-center gap-[6px]">
                        <input className="bg-fm-inner2 border-none rounded-[6px] h-[32px] pl-[8px] pr-[4px] text-fm-text-strong text-[12px] leading-[19px] outline-none flex-1 min-w-0 focus:shadow-[0_0_0_1px_var(--color-fm-brand)] disabled:cursor-not-allowed disabled:opacity-60" type="number" min={0} max={MAX_NET_WEIGHT_GRAMS} step={1} placeholder={t('Input Current Net Weight')} value={currentNetWeight} disabled={lockWeight} onFocus={(e) => e.target.select()} onChange={(e) => setCurrentNetWeight(clampWeight(sanitizeWeightInput(e.target)))} />
                        <span className="text-[12px] leading-[19px] text-fm-text-secondary shrink-0">g</span>
                      </div>
                    </div>
                    <div className="flex flex-col gap-[4px] flex-1">
                      <span className="text-[11px] leading-[16px] text-fm-text-secondary">{t('Total Net Weight')}</span>
                      {/* Total Net Weight is locked on edit: it is the
                          spool's factory full-weight and must not drift
                          after a row exists — only Current Net Weight
                          tracks consumption over time. Same trailing "g"
                          unit indicator as the sibling input. */}
                      <div className="flex items-center gap-[6px]">
                        <input className={`bg-fm-inner2 border-none rounded-[6px] h-[32px] pl-[8px] pr-[4px] text-fm-text-strong text-[12px] leading-[19px] outline-none flex-1 min-w-0 focus:shadow-[0_0_0_1px_var(--color-fm-brand)] ${isEdit || lockWeight ? 'opacity-60 cursor-not-allowed' : ''}`} type="number" min={0} max={MAX_NET_WEIGHT_GRAMS} step={1} placeholder={t('Input Total Net Weight')} value={totalNetWeight} readOnly={isEdit || lockWeight} disabled={isEdit || lockWeight} onFocus={(e) => e.target.select()} onChange={(e) => setTotalNetWeight(clampWeight(sanitizeWeightInput(e.target)))} />
                        <span className="text-[12px] leading-[19px] text-fm-text-secondary shrink-0">g</span>
                      </div>
                    </div>
                  </div>
                  {weightError && (
                    <div className="mt-[6px] text-[11px] leading-[16px] text-fm-warning">
                      {weightError}
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* 备注 — 唯一与云端同步的扩展字段，直接显示，不再折叠在高级设置里 */}
            <div className="flex flex-col gap-[4px]">
              <label className="text-[12px] leading-[19px] text-fm-text-secondary">{t('Note')}</label>
              <div className="relative">
                <textarea
                  className="bg-fm-inner2 border-none rounded-[6px] h-[110px] px-[12px] pt-[8px] pb-[4px] text-fm-text-strong text-[12px] leading-[19px] outline-none w-full focus:shadow-[0_0_0_1px_var(--color-fm-brand)] resize-none"
                  maxLength={50}
                  placeholder={t('Input Note')}
                  value={note}
                  onChange={(e) => setNote(e.target.value)}
                />
                <span className="absolute right-[12px] bottom-[4px] text-[12px] leading-[19px] text-fm-text-gray">{note.length}/50</span>
              </div>
            </div>
          </div>
        )}

        </div>{/* end p-[24px] content */}
        </div>{/* end scrollable wrapper */}

        {/* Footer */}
        <div className="flex items-center justify-between h-[60px] px-[16px] shrink-0">
          {!isEdit && mode === 'manual' && (
            <div className="flex items-center gap-[4px] w-[106px]">
              {/* STUDIO-18125: keep the up/down stepper, but also let the
                  user type the quantity directly. Reuses the Weight input
                  pattern (sanitizeWeightInput + select-on-focus, see
                  STUDIO-17958) so a backspace-clear followed by typing does
                  not leave a "0X" residue. Native spinner is hidden because
                  the external stepper buttons already cover that role and
                  the inline spinner would clash with the 24px row and the
                  "roll" suffix.
                  onClick={select} is intentional alongside onFocus={select}:
                  in Chromium the mouseup that follows focus cancels the
                  onFocus selection and drops the caret next to the default
                  "1", so a mouse-click + keypress yields "15" instead of
                  "5". The click event fires after mouseup, so re-selecting
                  there restores the all-select. Keyboard Tab never fires
                  click, so the Tab flow stays on the onFocus path. The
                  Weight inputs above deliberately do NOT do this because
                  users often edit weights mid-string (e.g. 1000 -> 100). */}
              <div className="flex-1 flex items-center gap-[4px] bg-fm-inner2 rounded-[6px] h-[24px] pl-[8px] pr-[4px] focus-within:shadow-[0_0_0_1px_var(--color-fm-brand)]">
                <input
                  data-testid="quantity-input"
                  className="flex-1 min-w-0 bg-transparent border-none outline-none p-0 text-[12px] leading-[19px] text-fm-text-strong appearance-none [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:m-0 [&::-webkit-outer-spin-button]:m-0"
                  type="number"
                  min={1}
                  max={99}
                  step={1}
                  value={quantity}
                  onFocus={(e) => e.target.select()}
                  onClick={(e) => e.currentTarget.select()}
                  onChange={(e) => setQuantity(clampQuantity(sanitizeWeightInput(e.target)))}
                  aria-label={t('Quantity')}
                />
                <span className="text-[11px] leading-[16px] text-fm-text-detail">{t('roll')}</span>
              </div>
              <div className="flex flex-col shrink-0 w-[18px] h-[24px]">
                <button className="flex-1 rounded-t-[6px] bg-fm-inner2 border-none cursor-pointer flex items-center justify-center text-fm-text-primary hover:bg-fm-hover" onClick={() => setQuantity(Math.min(99, quantity + 1))}>
                  <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M2.5 6.5l2.5-3 2.5 3" stroke="currentColor" strokeWidth="1"/></svg>
                </button>
                <button className="flex-1 rounded-b-[6px] bg-fm-inner2 border-none cursor-pointer flex items-center justify-center text-fm-text-primary hover:bg-fm-hover" onClick={() => setQuantity(Math.max(1, quantity - 1))}>
                  <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M2.5 3.5l2.5 3 2.5-3" stroke="currentColor" strokeWidth="1"/></svg>
                </button>
              </div>
            </div>
          )}
          {(isEdit || mode !== 'manual') && <div />}
          <div className="flex gap-[12px] items-center">
            <button data-testid="dialog-cancel" className="h-[30px] px-[32px] rounded-[8px] cursor-pointer text-[12px] leading-[19px] whitespace-nowrap transition-colors duration-150 bg-fm-input text-fm-text-primary border-none hover:bg-fm-hover" onClick={onClose}>{t('Cancel')}</button>
            <button
              data-testid="dialog-confirm"
              data-batch={isAmsBatch ? 'true' : 'false'}
              className="h-[30px] px-[32px] rounded-[8px] border-none cursor-pointer text-[12px] leading-[19px] font-medium whitespace-nowrap transition-colors duration-150 bg-fm-brand text-white hover:bg-fm-brand-hover disabled:opacity-40 disabled:cursor-default"
              disabled={!isValid}
              onClick={handleSubmit}
            >
              {isEdit
                ? t('Save')
                : (isAmsBatch ? t('Batch Add ({{count}})', { count: slotSelectionCount }) : t('Add'))}
            </button>
          </div>
        </div>
      </div>
    </div>
    {/* STUDIO-18385: duplicate RFID overwrite gate. Rendered as a sibling
        of the Add/Edit modal so the parent dialog stays mounted (and its
        selection state is preserved) while the user decides; canceling
        simply clears the pending state and leaves the user on the form. */}
    <ConfirmDialog
      open={!!rfidConfirmContent}
      title={rfidConfirmContent?.title ?? ''}
      message={rfidConfirmContent?.message}
      confirmText={rfidConfirmContent?.confirmText}
      onCancel={() => setRfidConfirm(null)}
      onConfirm={confirmRfidOverwrite}
    />
    </>
  );
}

/* AMS unit icon — 2×2 colored grid */
function AmsUnitIcon({ unit, isActive }: { unit: AmsUnit; isActive: boolean }) {
  const trays = unit.trays || [];
  const colors = [0, 1, 2, 3].map((i) => {
    const t = trays[i];
    return t && t.is_exists && t.color ? t.color : 'rgba(255,255,255,0.1)';
  });
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <rect x="1" y="1" width="18" height="18" rx="3"
        stroke={isActive ? 'var(--color-fm-brand)' : 'currentColor'} strokeWidth="1.2" fill="none" />
      <rect x="3" y="3" width="6" height="6" rx="1" fill={colors[0]} />
      <rect x="11" y="3" width="6" height="6" rx="1" fill={colors[1]} />
      <rect x="3" y="11" width="6" height="6" rx="1" fill={colors[2]} />
      <rect x="11" y="11" width="6" height="6" rx="1" fill={colors[3]} />
    </svg>
  );
}
